INSERT INTO public.diseases (slug, name, meta_description, overview, common_symptoms, possible_causes, risk_factors, diagnosis, lifestyle_tips, when_to_seek_care, prevention, category, is_common, severity, prevalence, age_group, gender, related_conditions, related_symptoms, related_questions, related_tools) VALUES
('sinusitis', 'Sinusitis', 'Learn about sinusitis symptoms, causes, diagnosis, and treatment options. Find out when to seek medical care and lifestyle tips for managing sinus inflammation.', 'Sinusitis is an inflammation of the sinuses, the air-filled cavities around the nasal passages. It can be acute or chronic, with symptoms including facial pain, congestion, and discharge.', '["Facial pain or pressure","Nasal congestion","Thick nasal discharge","Headache","Loss of smell"]'::jsonb, '["Viral infections","Bacterial infections","Allergic rhinitis","Nasal polyps","Deviated septum"]'::jsonb, '["Allergies","Asthma","Smoking","Immune system disorders","Frequent colds"]'::jsonb, 'Diagnosis typically involves a physical examination of the nasal passages and sinuses. Imaging tests like CT scans may be used for chronic cases. Nasal endoscopy can provide a detailed view of the sinus openings.', '["Stay hydrated","Use a humidifier","Practice good nasal hygiene","Avoid irritants","Manage allergies"]'::jsonb, 'Seek medical attention if symptoms last more than 10 days, worsen after improving, or include high fever, severe headache, or vision changes.', 'Prevent sinusitis by maintaining good nasal hygiene, managing allergies, staying hydrated, and avoiding smoke and other irritants.', 'Respiratory', TRUE, 'Mild to Moderate', 'Affects approximately 1 in 7 adults annually', 'All ages', 'Both', '["rhinitis","asthma","allergies"]'::jsonb, '["headache","nasal congestion","sore throat"]'::jsonb, '["why-is-my-nose-blocked","why-do-i-have-headaches"]'::jsonb, '["symptom-checker","allergy-assessment"]'::jsonb),
('eczema', 'Eczema', 'Comprehensive guide to eczema (atopic dermatitis) including symptoms, causes, treatment, and management strategies for healthy skin.', 'Eczema, also known as atopic dermatitis, is a chronic inflammatory skin condition characterized by itchy, red, and dry patches on the skin.', '["Itchy skin","Red or brown patches","Dry, cracked skin","Small bumps","Scaly skin"]'::jsonb, '["Genetic factors","Immune system dysfunction","Environmental triggers","Skin barrier defects"]'::jsonb, '["Family history of eczema","Allergies","Dry skin","Living in dry climates","Exposure to irritants"]'::jsonb, 'Diagnosis is typically clinical based on appearance and symptoms. A patch test may help identify specific triggers. Blood tests can rule out other conditions.', '["Moisturize daily","Avoid scratching","Use gentle soaps","Wear cotton clothing","Maintain cool environment"]'::jsonb, 'Consult a dermatologist if symptoms are severe, infected, or not responding to home care. Seek emergency care for signs of infection like pus or fever.', 'Prevent flare-ups by keeping skin moisturized, avoiding known triggers, maintaining humidity, and managing stress.', 'Skin', TRUE, 'Mild to Severe', 'Affects about 10-20% of children and 1-3% of adults', 'Children most affected', 'Both', '["asthma","hay-fever","food-allergies"]'::jsonb, '["dry-skin","rash","itching"]'::jsonb, '["why-is-my-skin-itchy","why-do-i-have-a-rash"]'::jsonb, '["skin-assessment","allergy-assessment"]'::jsonb),
('insomnia', 'Insomnia', 'Understanding insomnia: causes, symptoms, treatments, and sleep hygiene tips for better sleep quality.', 'Insomnia is a sleep disorder characterized by difficulty falling asleep, staying asleep, or getting restful sleep, despite adequate opportunity to sleep.', '["Difficulty falling asleep","Waking up frequently at night","Early morning awakening","Daytime fatigue","Irritability"]'::jsonb, '["Stress and anxiety","Depression","Chronic pain","Caffeine or alcohol","Irregular sleep schedule"]'::jsonb, '["Mental health conditions","Chronic illnesses","Medications","Aging","Shift work"]'::jsonb, 'Diagnosis involves sleep history, sleep diary, and possibly polysomnography. Mental health evaluation may be needed for underlying causes.', '["Establish regular sleep schedule","Create relaxing bedtime routine","Limit screen time before bed","Avoid caffeine and alcohol","Exercise regularly"]'::jsonb, 'Seek help if insomnia persists for more than 3 months, affects daily functioning, or is accompanied by other concerning symptoms.', 'Maintain good sleep hygiene, manage stress effectively, and address underlying health conditions promptly.', 'Mental Health', TRUE, 'Mild to Severe', 'Affects approximately 30% of adults', 'All ages, more common in adults', 'More common in women', '["anxiety","depression","chronic-pain"]'::jsonb, '["fatigue","headache","irritability"]'::jsonb, '["why-can''t-i-sleep","why-am-i-tired"]'::jsonb, '["sleep-checker","stress-assessment"]'::jsonb),
('migraine', 'Migraine', 'Learn about migraine headaches, including symptoms, triggers, treatment options, and prevention strategies.', 'Migraine is a neurological condition characterized by recurrent, severe headaches often accompanied by nausea, sensitivity to light, and visual disturbances.', '["Severe headache","Nausea and vomiting","Sensitivity to light","Sensitivity to sound","Visual disturbances"]'::jsonb, '["Genetic factors","Hormonal changes","Dietary triggers","Stress","Sleep disturbances"]'::jsonb, '["Family history","Female gender","Hormonal fluctuations","Certain foods","Dehydration"]'::jsonb, 'Diagnosis is clinical based on headache characteristics and symptoms. Imaging tests may rule out other causes like tumors or aneurysms.', '["Identify and avoid triggers","Stay hydrated","Maintain regular sleep","Manage stress","Exercise regularly"]'::jsonb, 'Seek emergency care for sudden, severe headaches, headaches after head injury, or headaches accompanied by neurological symptoms.', 'Prevent migraines by identifying triggers, maintaining healthy habits, and using preventive medications if prescribed.', 'Neurological', TRUE, 'Moderate to Severe', 'Affects about 15% of the global population', 'Most common 20-50 years', '3 times more common in women', '["tension-headache","cluster-headache","anxiety"]'::jsonb, '["headache","nausea","sensitivity-to-light"]'::jsonb, '["why-do-i-have-headaches","why-am-i-nauseous"]'::jsonb, '["symptom-checker","stress-assessment"]'::jsonb),
('anxiety', 'Anxiety', 'Comprehensive guide to anxiety disorders: symptoms, types, causes, and effective treatment options.', 'Anxiety is a normal response to stress, but when it becomes excessive or persistent, it can develop into an anxiety disorder that interferes with daily life.', '["Excessive worry","Restlessness","Fatigue","Difficulty concentrating","Irritability","Muscle tension"]'::jsonb, '["Genetic factors","Brain chemistry","Environmental stressors","Traumatic experiences","Medical conditions"]'::jsonb, '["Family history","Chronic stress","Trauma","Certain personality types","Substance use"]'::jsonb, 'Diagnosis involves clinical interview and psychological evaluation. Screening tools may help assess anxiety levels.', '["Practice relaxation techniques","Exercise regularly","Get enough sleep","Eat healthy diet","Limit caffeine and alcohol"]'::jsonb, 'Seek help if anxiety is interfering with daily activities, relationships, or work. Emergency care for panic attacks or suicidal thoughts.', 'Manage stress effectively, maintain healthy lifestyle, practice mindfulness, and seek early intervention for emerging symptoms.', 'Mental Health', TRUE, 'Mild to Severe', 'Affects approximately 284 million people globally', 'All ages', 'More common in women', '["depression","panic-disorder","insomnia"]'::jsonb, '["fatigue","irritability","difficulty-concentrating"]'::jsonb, '["why-am-i-anxious","why-do-i-feel-stressed"]'::jsonb, '["stress-assessment","anxiety-checker"]'::jsonb),
('diabetes', 'Diabetes', 'Learn about diabetes types, symptoms, risk factors, diagnosis, and management strategies for healthy living.', 'Diabetes is a chronic condition that affects how your body turns food into energy. There are two main types: Type 1 and Type 2 diabetes.', '["Increased thirst","Frequent urination","Extreme hunger","Unexplained weight loss","Fatigue","Blurred vision"]'::jsonb, '["Genetic factors","Autoimmune response (Type 1)","Insulin resistance (Type 2)","Lifestyle factors"]'::jsonb, '["Family history","Obesity","Lack of physical activity","Unhealthy diet","Age"]'::jsonb, 'Diagnosis involves blood tests including fasting glucose, A1C test, and oral glucose tolerance test.', '["Eat balanced diet","Exercise regularly","Monitor blood sugar","Take medications as prescribed","Quit smoking"]'::jsonb, 'Seek emergency care for symptoms of diabetic ketoacidosis (fruity breath, confusion) or hypoglycemia (shaking, sweating).', 'Prevent Type 2 diabetes by maintaining healthy weight, eating well, exercising regularly, and managing blood pressure.', 'Endocrine', TRUE, 'Chronic', 'Affects over 463 million adults globally', 'Type 2 more common in adults over 45', 'Both', '["hypertension","heart-disease","kidney-disease"]'::jsonb, '["fatigue","blurred-vision","weight-loss"]'::jsonb, '["why-am-i-tired","why-do-i-feel-thirsty"]'::jsonb, '["symptom-checker","nutrition-assessment"]'::jsonb),
('hypertension', 'Hypertension', 'Understanding high blood pressure: causes, risk factors, symptoms, and effective management strategies.', 'Hypertension, or high blood pressure, is a chronic medical condition where the pressure in the arteries is persistently elevated.', '["Often asymptomatic","Headaches","Dizziness","Blurred vision","Shortness of breath"]'::jsonb, '["Genetic factors","Age","Obesity","Sedentary lifestyle","High sodium intake","Stress"]'::jsonb, '["Family history","Older age","Obesity","Smoking","Excessive alcohol","High cholesterol"]'::jsonb, 'Diagnosis is made by measuring blood pressure over multiple visits. Ambulatory blood pressure monitoring may be used.', '["Maintain healthy weight","Exercise regularly","Eat low-sodium diet","Limit alcohol","Quit smoking"]'::jsonb, 'Seek emergency care for severe hypertension (BP > 180/120) or symptoms like chest pain, confusion, or stroke.', 'Prevent hypertension by maintaining healthy lifestyle, regular check-ups, managing stress, and limiting sodium intake.', 'Cardiovascular', TRUE, 'Chronic', 'Affects approximately 1.28 billion adults globally', 'More common in adults over 30', 'Men more common under 65, women over 65', '["heart-disease","stroke","kidney-disease"]'::jsonb, '["headache","dizziness","shortness-of-breath"]'::jsonb, '["why-do-i-have-headaches","why-am-i-dizzy"]'::jsonb, '["symptom-checker","heart-health-assessment"]'::jsonb),
('asthma', 'Asthma', 'Comprehensive guide to asthma: symptoms, triggers, treatment options, and management strategies for better breathing.', 'Asthma is a chronic respiratory condition characterized by inflammation and narrowing of the airways, causing difficulty breathing.', '["Wheezing","Shortness of breath","Chest tightness","Coughing","Difficulty breathing"]'::jsonb, '["Genetic factors","Environmental triggers","Allergies","Respiratory infections"]'::jsonb, '["Family history","Allergies","Exposure to irritants","Obesity","Smoking"]'::jsonb, 'Diagnosis involves spirometry testing, peak flow measurement, and allergy testing. Chest X-rays may rule out other conditions.', '["Identify and avoid triggers","Take medications as prescribed","Maintain clean environment","Exercise regularly","Manage stress"]'::jsonb, 'Seek emergency care for severe asthma attacks: difficulty breathing, blue lips, or inability to speak.', 'Prevent asthma attacks by avoiding triggers, taking preventive medications, maintaining good lung health.', 'Respiratory', TRUE, 'Mild to Severe', 'Affects over 235 million people globally', 'Children and adults', 'More common in boys as children, women as adults', '["allergies","eczema","rhinitis"]'::jsonb, '["cough","wheezing","shortness-of-breath"]'::jsonb, '["why-am-i-coughing","why-can''t-i-breathe"]'::jsonb, '["symptom-checker","allergy-assessment"]'::jsonb),
('arthritis', 'Arthritis', 'Learn about arthritis types, symptoms, treatment options, and lifestyle strategies for managing joint pain.', 'Arthritis refers to inflammation of one or more joints, causing pain, stiffness, and decreased mobility.', '["Joint pain","Joint stiffness","Swelling","Redness","Decreased range of motion"]'::jsonb, '["Age-related wear and tear","Autoimmune disorders","Infections","Genetic factors"]'::jsonb, '["Age","Obesity","Joint injury","Family history","Certain occupations"]'::jsonb, 'Diagnosis involves physical examination, X-rays, blood tests, and sometimes joint aspiration.', '["Maintain healthy weight","Exercise regularly","Use proper posture","Apply heat or cold","Manage stress"]'::jsonb, 'Seek help if joint pain is persistent, severe, or accompanied by fever, rash, or weight loss.', 'Prevent arthritis by maintaining healthy weight, exercising regularly, protecting joints from injury.', 'Musculoskeletal', TRUE, 'Mild to Severe', 'Affects over 350 million people globally', 'More common in adults over 65', 'Women more affected by rheumatoid arthritis', '["osteoarthritis","rheumatoid-arthritis","gout"]'::jsonb, '["joint-pain","stiffness","swelling"]'::jsonb, '["why-do-my-joints-hurt","why-is-my-knee-swollen"]'::jsonb, '["symptom-checker","pain-assessment"]'::jsonb),
('depression', 'Depression', 'Understanding depression: symptoms, types, causes, and effective treatment options for mental wellness.', 'Depression is a mood disorder that causes persistent feelings of sadness and loss of interest in activities once enjoyed.', '["Persistent sadness","Loss of interest","Fatigue","Changes in appetite","Sleep disturbances","Feelings of worthlessness"]'::jsonb, '["Genetic factors","Brain chemistry","Traumatic experiences","Chronic illness","Medications"]'::jsonb, '["Family history","Trauma","Chronic stress","Certain personality traits","Substance use"]'::jsonb, 'Diagnosis involves clinical interview and psychological evaluation. Screening tools like PHQ-9 may assist.', '["Stay connected with others","Exercise regularly","Eat healthy diet","Get enough sleep","Practice mindfulness"]'::jsonb, 'Seek help if symptoms persist for more than 2 weeks, affect daily functioning, or include thoughts of suicide.', 'Maintain strong social connections, manage stress effectively, seek early intervention for emotional changes.', 'Mental Health', TRUE, 'Mild to Severe', 'Affects over 280 million people globally', 'All ages', 'More common in women', '["anxiety","insomnia","chronic-pain"]'::jsonb, '["fatigue","sadness","loss-of-appetite"]'::jsonb, '["why-am-i-sad","why-do-i-have-no-energy"]'::jsonb, '["stress-assessment","mental-health-checker"]'::jsonb)
INSERT INTO public.symptoms (slug, name, meta_description, description, what_it_feels_like, possible_causes, related_conditions, when_to_see_doctor, self_care_tips, severity, duration, body_part, related_symptoms, related_questions, related_tools) VALUES
('headache', 'Headache', 'Learn about headache types, causes, symptoms, and treatment options. Find out when to seek medical care.', 'A headache is pain or discomfort in the head or upper neck region. It can range from mild to severe and may have various causes.', 'Headaches can feel like dull pressure, sharp throbbing, or tight squeezing. The pain may be localized to one area or spread across the entire head.', '["Tension","Migraine","Sinus pressure","Dehydration","Eye strain","Medication overuse"]'::jsonb, '["migraine","tension-headache","sinusitis","hypertension"]'::jsonb, 'Seek medical care for severe, sudden headaches, headaches accompanied by neurological symptoms, or persistent headaches.', '["Rest in dark quiet room","Apply heat or cold","Stay hydrated","Practice relaxation","Avoid triggers"]'::jsonb, 'Mild to Severe', 'Minutes to hours', 'Head', '["nausea","sensitivity-to-light","dizziness"]'::jsonb, '["why-do-i-have-headaches","why-am-i-dizzy"]'::jsonb, '["symptom-checker","stress-assessment"]'::jsonb),
('fatigue', 'Fatigue', 'Understanding fatigue: causes, symptoms, and effective strategies for overcoming tiredness.', 'Fatigue is a state of extreme tiredness or exhaustion that doesn''t improve with rest. It can affect physical and mental functioning.', 'Fatigue feels like overwhelming tiredness, lack of energy, difficulty concentrating, and decreased motivation. Activities that were once easy become challenging.', '["Sleep deprivation","Stress","Anemia","Thyroid disorders","Depression","Chronic fatigue syndrome"]'::jsonb, '["insomnia","depression","anemia","hypothyroidism"]'::jsonb, 'Seek help if fatigue persists despite adequate rest, or is accompanied by weight loss, pain, or other concerning symptoms.', '["Get enough sleep","Exercise regularly","Eat balanced meals","Manage stress","Stay hydrated"]'::jsonb, 'Mild to Severe', 'Chronic or intermittent', 'Whole body', '["weakness","difficulty-concentrating","sleepiness"]'::jsonb, '["why-am-i-tired","why-can''t-i-sleep"]'::jsonb, '["sleep-checker","stress-assessment"]'::jsonb),
('sore-throat', 'Sore Throat', 'Learn about sore throat causes, symptoms, home remedies, and when to see a doctor.', 'A sore throat is pain, scratchiness, or irritation of the throat that often worsens when swallowing.', 'A sore throat feels like a scratchy, burning, or raw sensation in the throat. Swallowing may be painful or difficult.', '["Viral infections","Bacterial infections","Allergies","Dry air","Acid reflux"]'::jsonb, '["cold","flu","tonsillitis","allergies"]'::jsonb, 'Seek care if sore throat lasts more than a week, is severe, or accompanied by high fever, difficulty breathing, or swollen glands.', '["Gargle with salt water","Drink warm liquids","Use throat lozenges","Get plenty of rest","Stay hydrated"]'::jsonb, 'Mild to Severe', '3-7 days', 'Throat', '["cough","runny-nose","fever"]'::jsonb, '["why-is-my-throat-sore","why-am-i-coughing"]'::jsonb, '["symptom-checker","allergy-assessment"]'::jsonb),
('nausea', 'Nausea', 'Understanding nausea: causes, symptoms, and effective ways to relieve queasiness.', 'Nausea is a feeling of discomfort in the stomach with an urge to vomit. It can be a symptom of many different conditions.', 'Nausea feels like a queasy, unsettled feeling in the stomach. It may be accompanied by sweating, dizziness, or an urge to throw up.', '["Viral infections","Motion sickness","Pregnancy","Medications","Food poisoning","Migraine"]'::jsonb, '["migraine","gastroenteritis","pregnancy","anxiety"]'::jsonb, 'Seek emergency care for persistent vomiting, severe abdominal pain, blood in vomit, or signs of dehydration.', '["Eat small frequent meals","Avoid strong smells","Stay hydrated","Get fresh air","Rest"]'::jsonb, 'Mild to Severe', 'Variable', 'Stomach', '["vomiting","dizziness","abdominal-pain"]'::jsonb, '["why-am-i-nauseous","why-do-i-feel-sick"]'::jsonb, '["symptom-checker","pregnancy-checker"]'::jsonb),
('dizziness', 'Dizziness', 'Learn about dizziness causes, symptoms, and effective management strategies for balance issues.', 'Dizziness is a sensation of lightheadedness, unsteadiness, or feeling like you might faint.', 'Dizziness feels like spinning, swaying, or feeling unbalanced. It may be accompanied by nausea, blurred vision, or weakness.', '["Inner ear problems","Low blood pressure","Dehydration","Anxiety","Medications","Anemia"]'::jsonb, '["vertigo","hypertension","anemia","anxiety"]'::jsonb, 'Seek care for severe or persistent dizziness, dizziness after head injury, or dizziness accompanied by chest pain.', '["Sit or lie down immediately","Stay hydrated","Avoid sudden movements","Manage stress","Get enough sleep"]'::jsonb, 'Mild to Severe', 'Seconds to hours', 'Head', '["lightheadedness","balance-problems","blurred-vision"]'::jsonb, '["why-am-i-dizzy","why-do-i-feel-faint"]'::jsonb, '["symptom-checker","heart-health-assessment"]'::jsonb),
('fever', 'Fever', 'Understanding fever: causes, symptoms, and when to seek medical attention for elevated temperature.', 'A fever is a temporary increase in body temperature, often caused by an infection or illness.', 'With a fever, you may feel hot, flushed, or chilled. You may have chills, sweating, headache, or muscle aches.', '["Viral infections","Bacterial infections","Inflammatory conditions","Medications","Immunizations"]'::jsonb, '["cold","flu","pneumonia","urinary-tract-infection"]'::jsonb, 'Seek care for fever over 104°F (40°C), persistent fever, fever with severe headache, or fever in infants under 3 months.', '["Stay hydrated","Rest","Take fever-reducing medication","Wear light clothing","Use cool compresses"]'::jsonb, 'Mild to Severe', 'Days', 'Whole body', '["chills","sweating","headache"]'::jsonb, '["why-do-i-have-a-fever","why-am-i-hot"]'::jsonb, '["symptom-checker","infection-assessment"]'::jsonb),
('cough', 'Cough', 'Learn about cough causes, types, home remedies, and when to see a doctor for persistent coughing.', 'A cough is a reflex action to clear the throat and airways of mucus, irritants, or foreign particles.', 'A cough feels like an irritation in the throat or chest that triggers a sudden expulsion of air. It may be dry or productive (with mucus).', '["Viral infections","Bacterial infections","Allergies","Asthma","Acid reflux","Smoking"]'::jsonb, '["cold","flu","asthma","bronchitis"]'::jsonb, 'Seek care for persistent cough (more than 3 weeks), cough with blood, chest pain, or difficulty breathing.', '["Stay hydrated","Use humidifier","Gargle with salt water","Take cough suppressants","Avoid irritants"]'::jsonb, 'Mild to Severe', 'Variable', 'Throat, chest', '["sore-throat","wheezing","shortness-of-breath"]'::jsonb, '["why-am-i-coughing","why-do-i-have-a-dry-cough"]'::jsonb, '["symptom-checker","allergy-assessment"]'::jsonb),
('back-pain', 'Back Pain', 'Understanding back pain: causes, symptoms, and effective treatment options for spinal health.', 'Back pain is discomfort or pain in the back, ranging from mild to severe. It can affect the upper, middle, or lower back.', 'Back pain feels like dull aching, sharp stabbing, or burning. It may be constant or intermittent, and may radiate to other areas.', '["Muscle strain","Herniated disc","Arthritis","Poor posture","Obesity","Sedentary lifestyle"]'::jsonb, '["herniated-disc","osteoarthritis","sciatica","fibromyalgia"]'::jsonb, 'Seek care for severe back pain, pain radiating to legs, numbness or tingling, or loss of bladder control.', '["Apply heat or cold","Practice good posture","Exercise regularly","Maintain healthy weight","Sleep on supportive mattress"]'::jsonb, 'Mild to Severe', 'Acute (less than 6 weeks) or chronic', 'Back', '["stiffness","muscle-tension","radiating-pain"]'::jsonb, '["why-does-my-back-hurt","why-is-my-back-stiff"]'::jsonb, '["symptom-checker","pain-assessment"]'::jsonb)
INSERT INTO public.causes (slug, name, meta_description, description, category, risk_level, related_conditions, related_symptoms, related_questions) VALUES
('dehydration', 'Dehydration', 'Learn about dehydration causes, symptoms, and effective strategies for staying properly hydrated.', 'Dehydration occurs when the body loses more fluids than it takes in, leading to an imbalance in electrolytes and bodily functions.', 'General Health', 'Moderate', '["heat-stroke","kidney-stones","constipation"]'::jsonb, '["thirst","fatigue","dry-mouth"]'::jsonb, '["why-am-i-tired","why-do-i-feel-thirsty"]'::jsonb),
('stress', 'Stress', 'Understanding stress: causes, effects, and effective management strategies for mental and physical well-being.', 'Stress is the body''s response to demands or pressures from the environment. It can be physical, emotional, or mental.', 'Mental Health', 'High', '["anxiety","depression","hypertension"]'::jsonb, '["fatigue","headache","muscle-tension"]'::jsonb, '["why-am-i-anxious","why-do-i-have-headaches"]'::jsonb),
('sleep-deprivation', 'Sleep Deprivation', 'Learn about the causes, effects, and solutions for insufficient sleep and poor sleep quality.', 'Sleep deprivation is a condition caused by not getting enough sleep or poor sleep quality over an extended period.', 'Sleep', 'High', '["insomnia","sleep-apnea","depression"]'::jsonb, '["fatigue","difficulty-concentrating","irritability"]'::jsonb, '["why-am-i-tired","why-can''t-i-sleep"]'::jsonb)
INSERT INTO public.body_parts (slug, name, meta_description, description, anatomy, common_conditions, common_symptoms, related_tests, category) VALUES
('head', 'Head', 'Learn about head anatomy, common conditions, and health tips for maintaining a healthy head.', 'The head contains the brain, skull, face, and sensory organs. It is the control center for the entire body.', 'The head consists of the cranium (skull), facial bones, brain, eyes, ears, nose, mouth, and various glands.', '["headache","migraine","sinusitis","concussion"]'::jsonb, '["headache","dizziness","vision-changes"]'::jsonb, '["ct-scan","mri","neurological-exam"]'::jsonb, 'Neurological'),
('heart', 'Heart', 'Learn about heart anatomy, common conditions, and strategies for maintaining cardiovascular health.', 'The heart is a muscular organ that pumps blood throughout the body. It is essential for life.', 'The heart has four chambers: two atria and two ventricles. It includes the coronary arteries, valves, and electrical conduction system.', '["hypertension","heart-attack","arrhythmia","heart-failure"]'::jsonb, '["chest-pain","shortness-of-breath","palpitations"]'::jsonb, '["ekg","echocardiogram","stress-test"]'::jsonb, 'Cardiovascular'),
('lungs', 'Lungs', 'Learn about lung anatomy, common respiratory conditions, and tips for maintaining healthy lungs.', 'The lungs are the primary organs of respiration, responsible for gas exchange between the body and the environment.', 'Each lung is divided into lobes. They contain bronchi, bronchioles, alveoli, and a network of blood vessels.', '["asthma","copd","pneumonia","lung-cancer"]'::jsonb, '["cough","shortness-of-breath","wheezing"]'::jsonb, '["pulmonary-function-test","chest-xray","ct-scan"]'::jsonb, 'Respiratory')
INSERT INTO public.lab_tests (slug, name, meta_description, description, purpose, procedure, preparation, normal_values, abnormal_results, cost_range, category, related_conditions, related_symptoms) VALUES
('blood-test', 'Blood Test', 'Learn about blood tests: purpose, types, preparation, and how to interpret results.', 'A blood test is a laboratory analysis of a blood sample to assess health status, diagnose conditions, or monitor treatments.', 'Blood tests can detect infections, nutrient deficiencies, organ function, cholesterol levels, blood sugar, and many other health markers.', 'A small blood sample is drawn from a vein, usually in the arm. The sample is sent to a laboratory for analysis.', 'Some blood tests require fasting for 8-12 hours. Your doctor will provide specific instructions.', 'Normal values vary by test type and laboratory. Common tests include complete blood count (CBC), chemistry panel, and lipid profile.', 'Abnormal results may indicate infection, anemia, diabetes, kidney or liver problems, or other conditions requiring further investigation.', '$50 - $500+ depending on the type and number of tests', 'General', '["anemia","diabetes","kidney-disease"]'::jsonb, '["fatigue","weakness","fever"]'::jsonb),
('ekg', 'EKG/ECG', 'Learn about electrocardiograms: purpose, procedure, and what the results mean for heart health.', 'An electrocardiogram (EKG or ECG) is a test that records the electrical activity of the heart.', 'EKGs detect heart rhythm abnormalities, heart attacks, heart muscle damage, and other cardiac conditions.', 'Small electrodes are placed on the chest, arms, and legs. The machine records the heart''s electrical activity over a few minutes.', 'No special preparation is needed. Wear comfortable clothing that can be easily removed.', 'A normal EKG shows regular heart rhythm with specific wave patterns (P wave, QRS complex, T wave).', 'Abnormal results may indicate arrhythmias, myocardial infarction, hypertrophy, or other heart conditions.', '$100 - $500', 'Cardiovascular', '["heart-attack","arrhythmia","hypertension"]'::jsonb, '["chest-pain","palpitations","shortness-of-breath"]'::jsonb),
('ct-scan', 'CT Scan', 'Learn about computed tomography scans: purpose, procedure, and safety considerations.', 'A CT (computed tomography) scan uses X-rays to create detailed cross-sectional images of the body.', 'CT scans diagnose tumors, infections, injuries, and structural abnormalities in various parts of the body.', 'The patient lies on a table that moves through a large doughnut-shaped machine. The machine takes X-ray images from multiple angles.', 'May require fasting, contrast dye, or specific clothing instructions depending on the area being scanned.', 'Normal results show no abnormal masses, lesions, or structural abnormalities.', 'Abnormal results may show tumors, fractures, bleeding, infections, or other conditions.', '$500 - $3000+', 'Imaging', '["cancer","stroke","trauma"]'::jsonb, '["headache","pain","swelling"]'::jsonb)
INSERT INTO public.medicines (slug, name, meta_description, description, uses, dosage, side_effects, precautions, category, related_conditions) VALUES
('ibuprofen', 'Ibuprofen', 'Learn about ibuprofen: uses, dosage, side effects, warnings, and precautions for this common NSAID pain reliever and anti-inflammatory medication.', 'Ibuprofen is a nonsteroidal anti-inflammatory drug (NSAID) used to reduce fever, pain, and inflammation. It works by blocking the production of prostaglandins, chemicals in the body that cause pain and swelling. It is one of the most widely used over-the-counter medications for mild to moderate pain and is available in various forms including tablets, capsules, liquids, and topical gels.', '["Relief of mild to moderate pain such as headache, toothache, and backache","Reduction of fever","Treatment of inflammation in conditions like arthritis","Relief of menstrual cramps","Management of muscle aches and joint pain"]'::jsonb, 'Adults and children over 12: 200-400 mg every 4-6 hours as needed, not exceeding 1200 mg per day without medical supervision. Take with food or milk to reduce stomach upset. For children under 12, dosing is based on weight and should be directed by a healthcare provider. Always use the lowest effective dose for the shortest duration necessary.', '["Stomach upset or pain","Heartburn and indigestion","Nausea and vomiting","Dizziness or headache","Fluid retention and swelling","Rash or mild allergic reactions"]'::jsonb, 'Do not take if you have a history of stomach ulcers or bleeding
INSERT INTO public.nutrition_items (slug, name, meta_description, description, type, benefits, food_sources, recommended_intake, deficiency_symptoms, toxicity, interactions, related_conditions, related_questions) VALUES
('vitamin-d', 'Vitamin D', 'Learn about Vitamin D: benefits, food sources, recommended intake, and deficiency symptoms.', 'Vitamin D is a fat-soluble vitamin that plays a crucial role in bone health, immune function, and overall well-being.', 'Vitamin', '["Supports bone health","Boosts immune function","Regulates mood","Supports muscle function","May reduce inflammation"]'::jsonb, '["Fatty fish","Egg yolks","Fortified dairy","Fortified cereals","Sunlight exposure"]'::jsonb, 'Adults: 600-800 IU daily (varies by age and health status)', '["Fatigue","Muscle weakness","Bone pain","Increased risk of infections","Mood changes"]'::jsonb, 'Excessive Vitamin D can cause hypercalcemia, kidney stones, and other health issues. Upper limit is generally 4000 IU/day for adults.', 'May interact with calcium supplements, certain medications, and medical conditions like kidney disease.', '["osteoporosis","rickets","seasonal-affective-disorder"]'::jsonb, '["why-am-i-tired","why-do-my-bones-hurt"]'::jsonb),
('protein', 'Protein', 'Learn about protein: benefits, sources, and recommended intake for optimal health and fitness.', 'Protein is a macronutrient essential for building and repairing tissues, muscle growth, and various bodily functions.', 'Macronutrient', '["Builds and repairs muscle","Supports immune function","Promotes satiety","Maintains healthy hair and nails","Supports hormone production"]'::jsonb, '["Lean meats","Fish","Eggs","Dairy products","Legumes","Tofu","Greek yogurt"]'::jsonb, 'Adults: 0.8 grams per kilogram of body weight daily (higher for athletes and older adults)', '["Muscle wasting","Fatigue","Weakened immunity","Slow wound healing","Hair loss"]'::jsonb, 'Excessive protein intake can strain kidneys and may contribute to dehydration. Generally well-tolerated in healthy individuals.', 'May interact with kidney disease, liver disease, and certain medications.', '["muscle-loss","malnutrition","chronic-fatigue"]'::jsonb, '["why-am-i-tired","why-do-i-lose-muscle"]'::jsonb),
('omega-3', 'Omega-3 Fatty Acids', 'Learn about Omega-3 fatty acids: benefits, food sources, and their role in heart and brain health.', 'Omega-3 fatty acids are polyunsaturated fats that are essential for heart health, brain function, and reducing inflammation.', 'Fatty Acid', '["Supports heart health","Improves brain function","Reduces inflammation","Supports eye health","May improve mood"]'::jsonb, '["Fatty fish (salmon, mackerel, sardines)","Chia seeds","Flaxseeds","Walnuts","Avocado"]'::jsonb, 'Adults: 250-500 mg of combined EPA and DHA daily', '["Dry skin","Poor memory","Mood swings","Joint pain","Fatigue"]'::jsonb, 'High doses may increase bleeding risk, especially for those taking blood thinners. Consult a healthcare provider before taking supplements.', 'May interact with blood-thinning medications, diabetes medications, and hypertension medications.', '["heart-disease","depression","arthritis"]'::jsonb, '["why-am-i-depressed","why-do-my-joints-hurt"]'::jsonb)
INSERT INTO public.vitamins (slug, name, meta_description, description, chemical_name, benefits, food_sources, recommended_daily_intake, deficiency_symptoms, toxicity, groups, related_conditions) VALUES
('vitamin-a', 'Vitamin A', 'Learn about Vitamin A: benefits, food sources, recommended intake, deficiency symptoms, and overdose risks for vision and immune health.', 'Vitamin A is a fat-soluble vitamin essential for vision, immune function, cell growth, and the maintenance of healthy skin and mucous membranes. It exists in two forms: preformed vitamin A (retinol) from animal sources and provitamin A carotenoids from plant sources.', NULL, '["Supports healthy vision, especially in low light","Strengthens the immune system","Promotes healthy skin and mucous membranes","Aids in cell growth and differentiation","Supports reproductive health"]'::jsonb, '["Liver (beef, chicken)","Sweet potatoes","Carrots","Spinach and kale","Fortified dairy products","Eggs","Mangoes and apricots"]'::jsonb, 'Adults: 700-900 mcg RAE per day (varies by sex and life stage)', '["Night blindness","Dry eyes","Frequent infections","Dry, scaly skin","Delayed growth in children"]'::jsonb, 'Excessive Vitamin A intake can cause hypervitaminosis A, leading to nausea, headache, liver damage, bone and joint pain, and in severe cases, coma. High intake during pregnancy can cause birth defects. Upper limit is 3000 mcg RAE per day for adults.', ARRAY['Fat-Soluble'], '["night-blindness","measles","anemia"]'::jsonb),
('vitamin-b', 'B Vitamins', 'Learn about B vitamins: benefits, food sources, recommended intake, deficiency symptoms, and the role of B-complex in energy and brain health.', 'B vitamins are a group of water-soluble vitamins that play essential roles in energy production, brain function, and cell metabolism. The B-complex includes B1 (thiamine), B2 (riboflavin), B3 (niacin), B5 (pantothenic acid), B6 (pyridoxine), B7 (biotin), B9 (folate), and B12 (cobalamin).', NULL, '["Supports energy production from food","Promotes healthy brain and nervous system function","Aids in red blood cell formation","Supports DNA synthesis and cell repair","Helps maintain healthy skin, hair, and eyes"]'::jsonb, '["Whole grains","Meat, poultry, and fish","Eggs and dairy products","Legumes and beans","Leafy green vegetables","Fortified cereals","Nuts and seeds"]'::jsonb, 'Varies by B vitamin; for example, B12: 2.4 mcg/day for adults, Folate: 400 mcg DFE/day for adults', '["Fatigue and weakness","Tingling or numbness in hands and feet","Memory problems","Mood changes and irritability","Anemia"]'::jsonb, 'B vitamins are water-soluble and excess is typically excreted in urine. However, very high doses of B6 (over 100 mg/day long-term) can cause nerve damage, and excess B3 (niacin) can cause flushing and liver damage. B9 excess can mask B12 deficiency.', ARRAY['Water-Soluble'], '["anemia","beriberi","pellagra"]'::jsonb),
('vitamin-c', 'Vitamin C', 'Learn about Vitamin C: benefits, food sources, recommended intake, deficiency symptoms, and its role in immunity and collagen production.', 'Vitamin C (ascorbic acid) is a water-soluble vitamin and powerful antioxidant that plays a vital role in immune function, collagen synthesis, wound healing, and the absorption of iron from plant-based foods. The body cannot produce or store vitamin C, so it must be obtained regularly from the diet.', NULL, '["Powerful antioxidant that protects cells from damage","Supports immune system function","Essential for collagen synthesis and wound healing","Enhances iron absorption from plant foods","Supports healthy skin, blood vessels, and cartilage"]'::jsonb, '["Citrus fruits (oranges, grapefruits)","Strawberries and kiwifruit","Bell peppers","Broccoli and Brussels sprouts","Tomatoes","Potatoes","Leafy green vegetables"]'::jsonb, 'Adults: 75-90 mg per day (higher for smokers and pregnant/nursing women)', '["Scurvy with bleeding gums","Easy bruising","Slow wound healing","Dry and splitting hair","Weakened immunity"]'::jsonb, 'Vitamin C is generally safe, but doses above 2000 mg per day can cause gastrointestinal discomfort, diarrhea, and may increase the risk of kidney stones in susceptible individuals. Upper limit is 2000 mg per day for adults.', ARRAY['Water-Soluble'], '["scurvy","common-cold","anemia"]'::jsonb),
('vitamin-d', 'Vitamin D', 'Learn about Vitamin D: benefits, food sources, recommended intake, deficiency symptoms, and its role in bone health and immunity.', 'Vitamin D is a fat-soluble vitamin that plays a crucial role in bone health, immune function, and overall well-being. Often called the ''sunshine vitamin'', it is produced by the body when skin is exposed to sunlight and is essential for calcium absorption and bone mineralization.', NULL, '["Supports bone health by aiding calcium absorption","Boosts immune function","Regulates mood and may reduce depression","Supports muscle function","May reduce inflammation"]'::jsonb, '["Fatty fish (salmon, mackerel, sardines)","Egg yolks","Fortified dairy products","Fortified cereals","Beef liver","Sunlight exposure"]'::jsonb, 'Adults: 600-800 IU (15-20 mcg) daily (varies by age and health status)', '["Fatigue","Muscle weakness","Bone pain","Increased risk of infections","Mood changes"]'::jsonb, 'Excessive Vitamin D can cause hypercalcemia (high blood calcium), leading to kidney stones, nausea, vomiting, weakness, and kidney damage. Upper limit is generally 4000 IU (100 mcg) per day for adults.', ARRAY['Fat-Soluble'], '["osteoporosis","rickets","seasonal-affective-disorder"]'::jsonb),
('vitamin-e', 'Vitamin E', 'Learn about Vitamin E: benefits, food sources, recommended intake, deficiency symptoms, and its role as an antioxidant for skin and immune health.', 'Vitamin E is a fat-soluble antioxidant vitamin that protects cell membranes from oxidative damage. It supports immune function, skin health, and blood vessel function, and plays a role in preventing the breakdown of vitamin A and unsaturated fatty acids.', NULL, '["Powerful antioxidant that protects cells from oxidative damage","Supports immune function","Promotes healthy skin and wound healing","Helps widen blood vessels and prevent clotting","May reduce the risk of certain chronic diseases"]'::jsonb, '["Vegetable oils (sunflower, safflower, wheat germ)","Nuts and seeds (almonds, sunflower seeds)","Spinach and broccoli","Fortified cereals","Avocados","Peanut butter"]'::jsonb, 'Adults: 15 mg (22.4 IU) per day', '["Muscle weakness","Vision problems","Immune system impairment","Numbness or tingling","Dry, damaged skin"]'::jsonb, 'Vitamin E from food is generally safe, but high-dose supplements may increase the risk of bleeding, especially in people taking blood thinners. Upper limit is 1000 mg (1500 IU) per day for adults.', ARRAY['Fat-Soluble'], '["heart-disease","cancer","alzheimers-disease"]'::jsonb),
('vitamin-k', 'Vitamin K', 'Learn about Vitamin K: benefits, food sources, recommended intake, deficiency symptoms, and its role in blood clotting and bone health.', 'Vitamin K is a fat-soluble vitamin essential for blood clotting, bone metabolism, and cardiovascular health. It exists in two main forms: vitamin K1 (phylloquinone) found in plants, and vitamin K2 (menaquinone) found in animal products and fermented foods.', NULL, '["Essential for blood clotting and wound healing","Supports bone health and density","Helps prevent calcium buildup in blood vessels","Supports cardiovascular health","Aids in calcium regulation"]'::jsonb, '["Leafy green vegetables (kale, spinach, collards)","Broccoli and Brussels sprouts","Fermented foods (natto, sauerkraut)","Egg yolks","Liver","Cheese and butter"]'::jsonb, 'Adults: 90-120 mcg per day (varies by sex)', '["Easy bruising","Excessive bleeding from wounds","Heavy menstrual periods","Oozing from gums or nose","Increased risk of bone fractures"]'::jsonb, 'Vitamin K from natural food sources is generally safe, but high doses of synthetic vitamin K3 (menadione) can cause hemolytic anemia and jaundice. No upper limit has been established for vitamin K1 and K2 from food and supplements.', ARRAY['Fat-Soluble'], '["osteoporosis","bleeding-disorders","cardiovascular-disease"]'::jsonb)
INSERT INTO public.health_guides (slug, name, meta_description, description, introduction, sections, key_takeaways, category, audience, difficulty, reading_time, related_conditions, related_symptoms, related_questions, related_tools) VALUES
('improve-sleep', 'How to Improve Sleep Quality', 'Comprehensive guide to improving sleep quality: tips, techniques, and strategies for better rest.', 'Getting quality sleep is essential for physical health, mental well-being, and overall quality of life.', 'Many people struggle with sleep issues, but there are practical steps you can take to improve your sleep quality and quantity.', '[{"title":"Create a Relaxing Bedtime Routine","content":"Establish a consistent routine that signals to your body it''s time to wind down. This may include reading, gentle stretching, meditation, or taking a warm bath."},{"title":"Optimize Your Sleep Environment","content":"Make sure your bedroom is dark, quiet, and cool. Use blackout curtains, earplugs, and a comfortable mattress and pillows."},{"title":"Maintain a Consistent Sleep Schedule","content":"Go to bed and wake up at the same time every day, even on weekends. This helps regulate your body''s internal clock."},{"title":"Limit Screen Time Before Bed","content":"The blue light from electronic devices can suppress melatonin production. Avoid screens at least 1 hour before bed."},{"title":"Watch What You Eat and Drink","content":"Avoid caffeine, alcohol, and heavy meals close to bedtime. Stay hydrated but limit fluids to avoid nighttime bathroom trips."}]'::jsonb, '["Establish a consistent bedtime routine","Keep your bedroom dark, quiet, and cool","Avoid screens before bed","Limit caffeine and alcohol intake","Exercise regularly but not right before bed"]'::jsonb, 'Sleep', 'General', 'Easy', 8, '["insomnia","sleep-apnea","anxiety"]'::jsonb, '["fatigue","difficulty-falling-asleep"]'::jsonb, '["why-can''t-i-sleep","why-am-i-tired"]'::jsonb, '["sleep-checker","stress-assessment"]'::jsonb),
('manage-stress', 'Effective Stress Management Strategies', 'Comprehensive guide to managing stress: techniques, exercises, and lifestyle changes for a calmer life.', 'Stress is a normal part of life, but chronic stress can have negative effects on physical and mental health.', 'Learning to manage stress effectively can improve your overall well-being, relationships, and quality of life.', '[{"title":"Identify Your Stressors","content":"The first step in managing stress is to identify what''s causing it. Keep a stress journal to track when you feel stressed and what triggers it."},{"title":"Practice Mindfulness and Meditation","content":"Mindfulness and meditation can help you stay present and reduce anxiety. Even 5-10 minutes a day can make a difference."},{"title":"Exercise Regularly","content":"Physical activity releases endorphins, which are natural mood lifters. Aim for at least 30 minutes of moderate exercise most days."},{"title":"Learn to Say No","content":"Setting boundaries is essential for managing stress. Don''t take on more than you can handle."},{"title":"Connect with Others","content":"Social support is important for stress management. Talk to friends, family, or a professional if you''re feeling overwhelmed."}]'::jsonb, '["Identify and understand your stress triggers","Practice mindfulness daily","Exercise regularly","Set boundaries and learn to say no","Seek social support when needed"]'::jsonb, 'Mental Health', 'General', 'Medium', 10, '["anxiety","depression","hypertension"]'::jsonb, '["fatigue","headache","irritability"]'::jsonb, '["why-am-i-anxious","why-do-i-feel-stressed"]'::jsonb, '["stress-assessment","anxiety-checker"]'::jsonb)
INSERT INTO public.mental_health (slug, name, meta_description, description, types, symptoms, causes, treatments, coping_strategies, category, related_conditions, related_questions, related_tools) VALUES
('generalized-anxiety', 'Generalized Anxiety Disorder', 'Learn about generalized anxiety disorder: symptoms, causes, and effective treatment options.', 'Generalized anxiety disorder (GAD) is a mental health condition characterized by excessive, uncontrollable worry about everyday things.', ARRAY['Generalized anxiety','Social anxiety','Panic disorder','Phobias'], '["Excessive worry","Restlessness","Fatigue","Difficulty concentrating","Irritability","Muscle tension","Sleep disturbances"]'::jsonb, 'The exact cause is unknown, but likely involves a combination of genetic factors, brain chemistry, environmental stressors, and life experiences.', '["Cognitive-behavioral therapy (CBT)","Medication (SSRIs, benzodiazepines)","Mindfulness-based stress reduction","Relaxation techniques"]'::jsonb, '["Deep breathing exercises","Progressive muscle relaxation","Mindfulness meditation","Regular exercise","Healthy lifestyle"]'::jsonb, 'Anxiety', '["depression","panic-disorder","insomnia"]'::jsonb, '["why-am-i-anxious","why-do-i-worry-so-much"]'::jsonb, '["stress-assessment","anxiety-checker"]'::jsonb),
('social-anxiety', 'Social Anxiety Disorder', 'Learn about social anxiety disorder: symptoms, causes, and strategies for managing social fears.', 'Social anxiety disorder is a mental health condition characterized by intense fear of social situations where one might be judged or embarrassed.', ARRAY['Performance anxiety','General social anxiety','Specific social phobias'], '["Fear of social situations","Excessive self-consciousness","Avoidance of social events","Physical symptoms (blushing, sweating, trembling)","Fear of being judged"]'::jsonb, 'May involve genetic factors, brain chemistry, learned behavior, and negative social experiences.', '["Cognitive-behavioral therapy (CBT)","Exposure therapy","Medication","Social skills training"]'::jsonb, '["Gradual exposure to social situations","Cognitive restructuring","Mindfulness","Breathing exercises","Building social skills"]'::jsonb, 'Anxiety', '["generalized-anxiety","depression","avoidant-personality-disorder"]'::jsonb, '["why-am-i-afraid-of-social-situations","why-do-i-feel-self-conscious"]'::jsonb, '["stress-assessment","anxiety-checker"]'::jsonb)
INSERT INTO public.womens_health (slug, name, meta_description, description, topics, related_conditions, related_questions, related_tools) VALUES
('menstrual-health', 'Menstrual Health', 'Learn about menstrual health: cycle phases, common irregularities, symptoms, and when to seek care for abnormal periods.', 'Menstrual health encompasses the regular functioning of the menstrual cycle, which is a key indicator of overall reproductive and hormonal health. A typical menstrual cycle lasts between 21 and 35 days, with bleeding lasting 2 to 7 days. Variations in cycle length, flow, and associated symptoms are common, but significant changes or severe symptoms may signal underlying conditions such as hormonal imbalances, polyps, fibroids, or thyroid disorders. Tracking the cycle and understanding what is normal for your body empowers early detection of issues and supports informed conversations with healthcare providers.', '{"common_symptoms":["Menstrual cramping (dysmenorrhea)","Bloating and fluid retention","Breast tenderness","Mood changes and irritability","Fatigue","Headaches or migraines","Acne flare-ups","Changes in bowel habits"],"risk_factors":["Stress and significant weight changes","Polycystic ovary syndrome (PCOS)","Thyroid disorders","Uterine fibroids or polyps","Endometriosis","Eating disorders or low body weight","Excessive exercise","Certain medications, including hormonal contraceptives"],"lifestyle_tips":["Track your cycle using an app or calendar to identify patterns","Maintain a balanced diet rich in iron, calcium, and omega-3 fatty acids","Stay hydrated and limit caffeine and salt before your period","Engage in regular, moderate exercise to reduce cramps and mood symptoms","Practice stress-reduction techniques such as yoga or mindfulness","Use heat therapy (heating pad) for cramp relief","Prioritize sleep to support hormonal balance"],"when_to_seek_care":"Consult a healthcare provider if your periods are consistently shorter than 21 days or longer than 35 days, bleeding lasts more than 7 days, you soak through a pad or tampon every hour for several hours, you experience severe pain that disrupts daily activities, or you miss periods for three months in a row (and are not pregnant). Seek immediate care for sudden heavy bleeding with dizziness or fainting."}'::jsonb, '["pcos","endometriosis","menopause"]'::jsonb, '["why-is-my-period-irregular","why-do-i-have-severe-menstrual-cramps"]'::jsonb, '["cycle-tracker","symptom-checker"]'::jsonb),
('pcos', 'Polycystic Ovary Syndrome (PCOS)', 'Learn about PCOS: symptoms, hormonal causes, long-term risks, and lifestyle-based management strategies.', 'Polycystic ovary syndrome (PCOS) is one of the most common endocrine disorders affecting women of reproductive age, with an estimated prevalence of 6 to 12 percent worldwide. It is defined by a combination of irregular menstrual cycles, elevated androgen (male hormone) levels, and polycystic-appearing ovaries on ultrasound. PCOS is a leading cause of infertility and is closely linked to insulin resistance, which increases the risk of type 2 diabetes, metabolic syndrome, and cardiovascular disease. While there is no cure, early diagnosis and ongoing management through lifestyle changes, medication, and regular monitoring can effectively control symptoms and reduce long-term health risks.', '{"common_symptoms":["Irregular or absent periods","Excess facial or body hair (hirsutism)","Severe or cystic acne","Thinning hair or male-pattern baldness","Weight gain or difficulty losing weight","Darkening of skin in folds (acanthosis nigricans)","Difficulty conceiving","Oily skin"],"risk_factors":["Family history of PCOS","Insulin resistance and obesity","Sedentary lifestyle","Low-grade chronic inflammation","Type 2 diabetes or gestational diabetes in family","Higher levels of androgens during puberty"],"lifestyle_tips":["Focus on weight management; even a 5-10% weight loss can restore ovulation","Adopt a low-glycemic-index diet rich in whole grains, vegetables, and lean protein","Engage in at least 150 minutes of moderate exercise per week","Include strength training to improve insulin sensitivity","Limit processed foods and added sugars","Work with an endocrinologist or gynecologist on medication options","Monitor mental health, as anxiety and depression are more common in PCOS"],"when_to_seek_care":"See a healthcare provider if you have irregular or absent periods, unexplained weight gain with acne or excess hair growth, or difficulty getting pregnant. Seek urgent care for sudden severe pelvic pain, especially with vomiting, which can indicate ovarian torsion. Regular check-ups are important to screen for diabetes, high blood pressure, and cholesterol if you have PCOS."}'::jsonb, '["menstrual-health","diabetes","endometriosis"]'::jsonb, '["why-are-my-periods-irregular","why-am-i-gaining-weight"]'::jsonb, '["hormone-assessment","symptom-checker"]'::jsonb),
('endometriosis', 'Endometriosis', 'Learn about endometriosis: symptoms, causes, diagnosis, and treatment options for this chronic pelvic condition.', 'Endometriosis is a chronic, often painful condition in which endometrial-like tissue grows outside the uterus, most commonly on the ovaries, fallopian tubes, and pelvic lining. This tissue responds to hormonal changes, causing inflammation, scarring, and adhesions. The condition affects roughly 1 in 10 women of reproductive age and is a leading cause of infertility. Symptoms vary widely and do not always correlate with disease severity, which contributes to an average diagnostic delay of 7 to 10 years. While endometriosis has no cure, a combination of medical therapy, surgery, and lifestyle strategies can effectively manage pain and preserve fertility.', '{"common_symptoms":["Severe menstrual cramps (dysmenorrhea)","Chronic pelvic or lower back pain","Pain during or after intercourse","Painful bowel movements or urination during periods","Heavy or irregular bleeding","Fatigue","Digestive issues such as bloating, diarrhea, or constipation","Difficulty conceiving"],"risk_factors":["Family history of endometriosis","Short menstrual cycles (less than 27 days)","Heavy periods lasting more than 7 days","Never having given birth","Early onset of menstruation (before age 11)","Low body mass index","Uterine or reproductive tract abnormalities"],"lifestyle_tips":["Apply heat (heating pads, warm baths) to relieve pelvic pain","Follow an anti-inflammatory diet rich in omega-3s, fruits, and vegetables","Limit red meat, caffeine, and alcohol, which may worsen inflammation","Engage in gentle, regular exercise such as yoga, walking, or swimming","Practice stress management through meditation or cognitive behavioral therapy","Keep a symptom and pain diary to share with your care team","Consider pelvic floor physical therapy for muscle tension relief"],"when_to_seek_care":"Seek evaluation for pelvic pain that disrupts daily life, painful periods that do not respond to over-the-counter pain relief, pain during intercourse, or difficulty becoming pregnant. Seek immediate care for sudden severe abdominal pain, especially with fever or vomiting, which can signal a ruptured cyst or ovarian torsion."}'::jsonb, '["menstrual-health","pcos","infertility"]'::jsonb, '["why-do-i-have-severe-period-pain","why-does-intercourse-hurt"]'::jsonb, '["pain-tracker","symptom-checker"]'::jsonb),
('menopause', 'Menopause', 'Learn about menopause: stages, common symptoms, long-term health impacts, and management strategies.', 'Menopause is defined as the permanent cessation of menstruation, confirmed after 12 consecutive months without a period. It typically occurs between ages 45 and 55, with the average age around 51. The transition, called perimenopause, can last several years and is marked by fluctuating estrogen and progesterone levels. These hormonal changes produce a range of symptoms including hot flashes, night sweats, sleep disturbances, mood changes, and vaginal dryness. Menopause also increases the risk of osteoporosis and cardiovascular disease due to the protective effects of estrogen being lost. While menopause is a natural life stage, a range of lifestyle, non-hormonal, and hormonal therapies can ease symptoms and protect long-term health.', '{"common_symptoms":["Hot flashes and night sweats","Irregular periods leading to cessation","Sleep disturbances and insomnia","Mood swings, irritability, or anxiety","Vaginal dryness and discomfort","Decreased libido","Fatigue and difficulty concentrating (''brain fog'')","Weight gain, particularly around the abdomen"],"risk_factors":["Smoking, which can trigger earlier menopause","Family history of early menopause","Certain cancer treatments such as chemotherapy or radiation","Surgical removal of ovaries (oophorectomy)","Autoimmune conditions","Increasing age (natural progression)"],"lifestyle_tips":["Eat a diet rich in calcium and vitamin D to protect bone health","Engage in weight-bearing and resistance exercise to prevent osteoporosis","Dress in layers and keep the bedroom cool to manage hot flashes","Limit caffeine, alcohol, and spicy foods, which can trigger hot flashes","Practice relaxation techniques such as deep breathing and yoga","Maintain a consistent sleep schedule and good sleep hygiene","Stay connected with a healthcare provider to discuss hormone or non-hormonal therapies"],"when_to_seek_care":"Talk to a healthcare provider if symptoms such as hot flashes, sleep problems, or mood changes interfere with daily life, or if you experience bleeding after menopause, which should always be evaluated. Seek urgent care for heavy bleeding, severe pelvic pain, or signs of cardiovascular issues such as chest pain or shortness of breath."}'::jsonb, '["menstrual-health","osteoporosis","depression"]'::jsonb, '["why-am-i-having-hot-flashes","why-cant-i-sleep"]'::jsonb, '["menopause-tracker","symptom-checker"]'::jsonb),
('breast-health', 'Breast Health', 'Learn about breast health: screening, common changes, risk factors, and early detection of breast conditions.', 'Breast health refers to the ongoing awareness, screening, and care of breast tissue throughout a woman''s life. Breasts undergo normal changes influenced by hormones, age, and life events such as pregnancy and menopause. Understanding what is normal for your body allows earlier detection of unusual changes, which is critical because breast cancer is the most commonly diagnosed cancer in women worldwide. Early detection through self-awareness, clinical exams, and mammography significantly improves outcomes. Most breast changes are benign, including cysts and fibrocystic changes, but any new or persistent change should be evaluated promptly by a healthcare professional.', '{"common_symptoms":["A new lump or thickening in the breast or underarm","Change in breast size, shape, or contour","Nipple discharge, especially if bloody or clear","Skin dimpling, redness, or puckering","Nipple retraction or inversion","Persistent breast or nipple pain","Scaliness or rash on the nipple","Swelling or warmth in part of the breast"],"risk_factors":["Increasing age","Family history of breast or ovarian cancer","Inherited mutations such as BRCA1 or BRCA2","Early menstruation (before age 12) or late menopause (after age 55)","Dense breast tissue","Long-term hormone replacement therapy","Excess body weight after menopause","Smoking and high alcohol consumption"],"lifestyle_tips":["Perform regular breast self-awareness to notice changes early","Follow recommended screening guidelines for mammograms and clinical exams","Maintain a healthy weight, especially after menopause","Limit alcohol to no more than one drink per day","Engage in regular physical activity","Eat a diet rich in vegetables, fruits, and whole grains","Discuss personal risk factors with your healthcare provider to plan screening"],"when_to_seek_care":"See a healthcare provider promptly if you notice a new lump, a change in breast size or shape, nipple discharge (especially bloody or clear), skin changes such as dimpling or redness, or persistent pain in one area. Never delay evaluation of a change that persists through one full menstrual cycle. Seek urgent care for rapidly growing, painful swelling with fever, which may indicate an infection (mastitis) or abscess."}'::jsonb, '["menopause","breast-cancer","mastitis"]'::jsonb, '["why-do-my-breasts-hurt","when-should-i-start-mammograms"]'::jsonb, '["breast-self-exam-guide","risk-assessment"]'::jsonb)
INSERT INTO public.mens_health (slug, name, meta_description, description, topics, related_conditions, related_questions, related_tools) VALUES
('prostate-health', 'Prostate Health', 'Learn about prostate health: common conditions like BPH and prostatitis, symptoms, risk factors, screening, and lifestyle tips for maintaining a healthy prostate.', 'The prostate is a small walnut-sized gland in men that produces fluid for semen. As men age, the prostate is prone to several conditions, most commonly benign prostatic hyperplasia (BPH), prostatitis (inflammation), and prostate cancer. Prostate health focuses on early detection, symptom management, and prevention. Regular screening, a healthy lifestyle, and awareness of urinary and sexual changes are key to maintaining prostate health throughout life.', '{"common_symptoms":["Frequent urination, especially at night","Difficulty starting or stopping urination","Weak or interrupted urine stream","Pain or burning during urination","Blood in urine or semen","Pelvic or lower back pain","Painful ejaculation"],"risk_factors":["Age over 50","Family history of prostate cancer","African ancestry","Obesity and sedentary lifestyle","Diet high in red meat and high-fat dairy","Smoking","History of prostatitis or STIs"],"lifestyle_tips":["Eat a diet rich in fruits, vegetables, and whole grains","Include tomatoes and cruciferous vegetables for prostate-protective nutrients","Stay physically active with regular exercise","Maintain a healthy weight","Limit red meat and high-fat dairy products","Stay hydrated but reduce fluids before bedtime","Schedule regular prostate screenings after age 50"],"when_to_seek_care":"See a healthcare provider if you experience frequent or painful urination, blood in urine or semen, persistent pelvic pain, or sudden changes in urinary habits. Men over 50 (or 40-45 with risk factors) should discuss PSA screening with their doctor. Seek immediate care for inability to urinate or severe pelvic pain."}'::jsonb, '["prostate-cancer","bph","prostatitis","urinary-tract-infection"]'::jsonb, '["why-am-i-tired","why-do-i-have-headaches"]'::jsonb, '["symptom-checker","hormone-checker"]'::jsonb),
('testosterone', 'Testosterone', 'Understand testosterone levels in men: symptoms of low testosterone, causes, diagnosis, treatment options, and natural ways to maintain hormonal balance.', 'Testosterone is the key male sex hormone produced mainly in the testicles. It regulates sex drive, bone mass, fat distribution, muscle strength, and red blood cell production. Testosterone levels naturally decline with age (about 1% per year after age 30), but abnormally low levels can cause a condition called hypogonadism. Symptoms may include fatigue, low libido, depression, and loss of muscle mass. Diagnosis involves blood tests, and treatment may include lifestyle changes or testosterone replacement therapy (TRT) when clinically indicated.', '{"common_symptoms":["Reduced sex drive (low libido)","Erectile dysfunction","Fatigue and decreased energy","Loss of muscle mass and strength","Increased body fat","Mood changes, irritability, or depression","Decreased bone density","Difficulty concentrating"],"risk_factors":["Aging (natural decline after 30)","Obesity and metabolic syndrome","Type 2 diabetes","Chronic illness or stress","Testicular injury or infection","Certain medications (opioids, steroids)","Genetic conditions like Klinefelter syndrome","Excessive alcohol consumption"],"lifestyle_tips":["Get 7-9 hours of quality sleep per night","Engage in regular resistance training and HIIT","Maintain a balanced diet with healthy fats, protein, and zinc","Manage chronic stress through mindfulness or meditation","Maintain a healthy body weight","Limit alcohol and avoid tobacco","Get adequate vitamin D from sunlight or supplements","Avoid excessive endurance training without recovery"],"when_to_seek_care":"Consult a healthcare provider if you experience persistent low libido, fatigue, mood changes, or unexplained muscle loss. A blood test measuring total testosterone (ideally morning levels) can confirm deficiency. Discuss the benefits and risks of testosterone therapy with an endocrinologist or urologist rather than self-medicating."}'::jsonb, '["hypogonadism","depression","diabetes","obesity"]'::jsonb, '["why-am-i-tired","why-am-i-gaining-weight"]'::jsonb, '["hormone-checker","fitness-assessment"]'::jsonb),
('erectile-dysfunction', 'Erectile Dysfunction', 'Learn about erectile dysfunction (ED): causes, symptoms, risk factors, treatment options, and when to seek medical care for this common men''s health condition.', 'Erectile dysfunction (ED) is the persistent inability to achieve or maintain an erection firm enough for sexual intercourse. It is a common condition affecting millions of men, with prevalence increasing with age. ED is often an early warning sign of underlying cardiovascular disease, diabetes, or hormonal imbalances, as it reflects impaired blood flow or nerve function. Causes can be physical, psychological, or a combination of both. Effective treatments range from lifestyle changes and oral medications to therapy and advanced medical interventions.', '{"common_symptoms":["Difficulty achieving an erection","Difficulty maintaining an erection during sex","Reduced sexual desire","Erections that are less firm than usual","Inability to get an erection at all"],"risk_factors":["Cardiovascular disease and atherosclerosis","Diabetes","High blood pressure and high cholesterol","Obesity and metabolic syndrome","Smoking and tobacco use","Excessive alcohol or substance use","Depression, anxiety, or chronic stress","Certain medications (antidepressants, blood pressure drugs)"],"lifestyle_tips":["Quit smoking and avoid tobacco products","Limit alcohol consumption","Exercise regularly to improve blood flow","Maintain a healthy weight and diet","Manage stress, anxiety, and depression","Communicate openly with your partner","Get adequate sleep","Review medications with your doctor for side effects"],"when_to_seek_care":"See a doctor if ED persists for more than a few weeks, as it may indicate an underlying health condition like heart disease or diabetes. Seek immediate care if ED occurs suddenly with other symptoms like chest pain or shortness of breath. A urologist can evaluate causes and recommend treatments including medications, therapy, or other interventions."}'::jsonb, '["hypertension","diabetes","depression","hypogonadism"]'::jsonb, '["why-am-i-anxious","why-am-i-tired"]'::jsonb, '["symptom-checker","heart-health-assessment","hormone-checker"]'::jsonb),
('hair-loss', 'Hair Loss', 'Understand male hair loss: types like male pattern baldness, causes, prevention strategies, and treatment options to slow or reverse hair loss.', 'Hair loss is a common concern for men, with male pattern baldness (androgenetic alopecia) being the most prevalent type, affecting up to 70% of men during their lifetime. It is driven by genetics and the hormone dihydrotestosterone (DHT), which shrinks hair follicles over time. Other causes include stress, nutritional deficiencies, medications, and medical conditions like thyroid disorders. While hair loss is generally harmless, it can significantly impact self-esteem. Various treatments, from medications to procedures, can slow progression or restore hair.', '{"common_symptoms":["Receding hairline at the temples","Thinning at the crown of the head","Horseshoe pattern of hair loss","Increased hair shedding on pillows or in shower","Gradual miniaturization of hair shafts","Patchy or sudden hair loss"],"risk_factors":["Family history of male pattern baldness","Aging","High levels of DHT","Chronic stress","Nutritional deficiencies (iron, zinc, vitamin D)","Smoking","Certain medications and medical treatments","Thyroid disorders"],"lifestyle_tips":["Maintain a balanced diet rich in protein, iron, and vitamins","Manage stress through exercise and relaxation techniques","Avoid tight hairstyles that pull on hair","Use gentle hair care products","Consider FDA-approved treatments like minoxidil","Consult a dermatologist about finasteride or other medications","Avoid smoking, which restricts blood flow to follicles","Get enough sleep to support overall health"],"when_to_seek_care":"Consult a dermatologist if you experience sudden or patchy hair loss, hair loss accompanied by itching or scaling, or if hair loss causes significant distress. Early intervention offers the best chance of slowing progression. Seek care for hair loss related to medications or underlying conditions like thyroid disease."}'::jsonb, '["thyroid-disorder","anemia","depression"]'::jsonb, '["why-am-i-anxious","why-do-i-have-acne"]'::jsonb, '["symptom-checker","nutrition-assessment"]'::jsonb),
('male-fertility', 'Male Fertility', 'Learn about male fertility: factors affecting sperm health, common causes of infertility, diagnosis, lifestyle tips, and treatment options.', 'Male fertility plays a role in about 40-50% of all infertility cases. It depends on the production of healthy sperm, proper sperm transport, and adequate sexual function. Factors affecting fertility include hormone levels, lifestyle habits, environmental exposures, and underlying medical conditions like varicocele or infections. A semen analysis is the primary diagnostic tool, evaluating sperm count, motility, and morphology. Many causes of male infertility can be addressed through lifestyle changes, medical treatment, or assisted reproductive technologies.', '{"common_symptoms":["Difficulty conceiving after 12 months of trying","Low sperm count (oligospermia)","Reduced sperm motility","Abnormal sperm morphology","Hormonal symptoms like low libido or fatigue","Swelling or lump in the testicles","Erectile or ejaculatory dysfunction"],"risk_factors":["Varicocele (enlarged veins in the scrotum)","History of infections or STIs","Exposure to heat (hot tubs, tight underwear)","Smoking, alcohol, and recreational drugs","Obesity and poor diet","Exposure to environmental toxins and pesticides","Certain medications and anabolic steroids","Age-related decline in sperm quality"],"lifestyle_tips":["Maintain a healthy weight through diet and exercise","Eat foods rich in antioxidants, zinc, and omega-3 fatty acids","Avoid smoking, recreational drugs, and excessive alcohol","Limit heat exposure to the testicles","Manage stress and get adequate sleep","Avoid anabolic steroids and certain medications","Stay hydrated and reduce caffeine intake","Get regular check-ups to address underlying conditions"],"when_to_seek_care":"See a fertility specialist if you and your partner have been unable to conceive after 12 months of regular unprotected sex (or 6 months if the female partner is over 35). Seek evaluation sooner if you have a history of testicular injury, infections, or hormonal symptoms. A urologist or reproductive endocrinologist can perform semen analysis and recommend treatments."}'::jsonb, '["varicocele","hypogonadism","diabetes","depression"]'::jsonb, '["why-am-i-tired","why-am-i-gaining-weight"]'::jsonb, '["hormone-checker","fitness-assessment","nutrition-assessment"]'::jsonb)
INSERT INTO public.childrens_health (slug, name, meta_description, description, topics, related_conditions, related_questions, related_tools) VALUES
('vaccination-schedule', 'Vaccination Schedule', 'Learn about childhood vaccination schedules: recommended immunizations from birth through adolescence, timing, importance, side effects, and how to keep your child''s vaccines on track.', 'Vaccination is one of the most effective public health interventions in history, protecting children from serious infectious diseases such as measles, polio, whooping cough, and diphtheria. A vaccination schedule outlines the recommended ages and intervals at which children should receive specific immunizations, typically beginning at birth and continuing through adolescence. Following the schedule ensures that children develop immunity at the right time, when they are most vulnerable and when the immune response is most effective. Delaying or skipping vaccines leaves children unprotected and can lead to outbreaks of preventable diseases. Parents should keep an up-to-date immunization record and discuss any concerns with their pediatrician.', '{"common_symptoms":["Mild fever within 24-48 hours after vaccination","Soreness, redness, or swelling at the injection site","Fussiness or increased crying in infants","Mild rash (e.g., after MMR or varicella vaccine)","Drowsiness or temporary loss of appetite","Swollen lymph nodes"],"risk_factors":["Missed or delayed vaccine doses","Living in areas with low community vaccination coverage","Travel to regions with endemic diseases","Underlying immunodeficiency conditions","Premature birth requiring adjusted scheduling","Lack of access to healthcare or immunization records","Misinformation or vaccine hesitancy among caregivers"],"lifestyle_tips":["Keep an up-to-date written or digital immunization record","Schedule well-child visits on time to stay on track","Use a cool, damp cloth to ease soreness at the injection site","Offer extra fluids and comfort after vaccinations","Discuss any vaccine concerns openly with your pediatrician","Inform the doctor of any prior reactions or severe allergies before vaccination","Stay informed about catch-up schedules if a dose is missed","Keep track of seasonal vaccines like the annual flu shot"],"when_to_seek_care":"Seek immediate medical attention if your child shows signs of a severe allergic reaction (anaphylaxis) after vaccination, such as difficulty breathing, swelling of the face or throat, hives, or collapse. Contact your pediatrician for persistent fever above 40°C (104°F), seizures, extreme lethargy, or inconsolable crying lasting more than three hours. Mild side effects are normal, but any unusual or concerning symptoms should be reported to a healthcare provider."}'::jsonb, '["measles","whooping-cough","influenza","polio"]'::jsonb, '["why-does-my-child-have-a-fever","why-does-my-child-have-a-rash"]'::jsonb, '["symptom-checker","vaccination-tracker"]'::jsonb),
('common-childhood-illnesses', 'Common Childhood Illnesses', 'Understand common childhood illnesses like colds, ear infections, chickenpox, and gastroenteritis: symptoms, causes, home care, and when to see a pediatrician.', 'Children are especially susceptible to common illnesses because their immune systems are still developing and they are in close contact with other children in daycare and school settings. The most frequent childhood illnesses include the common cold, ear infections (otitis media), strep throat, chickenpox, hand-foot-and-mouth disease, and viral gastroenteritis. Most of these illnesses are mild and resolve on their own with supportive care, but some can lead to complications if not properly managed. Recognizing symptoms early, practicing good hygiene, and knowing when to seek medical care helps parents navigate these common health challenges and keep their children comfortable during recovery.', '{"common_symptoms":["Runny or stuffy nose and sneezing","Fever, often low-grade","Cough and sore throat","Ear pulling or ear pain (ear infection)","Vomiting and diarrhea (gastroenteritis)","Rashes or skin spots (chickenpox, hand-foot-and-mouth)","Reduced appetite and irritability","Fatigue and decreased activity"],"risk_factors":["Attendance at daycare or preschool","Young age, especially under 5 years","Incomplete or missing vaccinations","Exposure to secondhand smoke","Poor hand hygiene habits","Weakened immune system or chronic conditions","Bottle feeding while lying down (ear infections)","Seasonal exposure during winter months"],"lifestyle_tips":["Encourage frequent handwashing with soap and water","Ensure your child stays well-hydrated during illness","Provide plenty of rest and a comfortable environment","Use a humidifier to ease congestion and cough","Teach children to cover coughs and sneezes properly","Keep sick children home to prevent spreading illness","Follow the recommended vaccination schedule","Avoid exposing children to secondhand smoke"],"when_to_seek_care":"Contact a pediatrician if your child is under 3 months old with a fever of 38°C (100.4°F) or higher, shows signs of dehydration (dry mouth, no tears when crying, fewer wet diapers), has difficulty breathing, persistent vomiting, a rash that spreads rapidly, or a fever lasting more than three days. Seek emergency care for severe breathing difficulty, blue lips, extreme lethargy, or a stiff neck with fever."}'::jsonb, '["common-cold","ear-infection","chickenpox","gastroenteritis","strep-throat"]'::jsonb, '["why-does-my-child-have-a-fever","why-does-my-child-have-a-cough"]'::jsonb, '["symptom-checker","fever-tracker"]'::jsonb),
('child-nutrition', 'Child Nutrition', 'Learn about child nutrition: balanced diets for growing kids, essential nutrients, portion sizes, picky eating, and how to build lifelong healthy eating habits.', 'Proper nutrition during childhood is essential for physical growth, cognitive development, immune function, and the establishment of lifelong healthy eating habits. Children have unique nutritional needs that change as they grow, requiring adequate intake of macronutrients (proteins, carbohydrates, and healthy fats) and micronutrients (such as iron, calcium, vitamin D, and zinc). A balanced diet built around fruits, vegetables, whole grains, lean proteins, and dairy supports healthy weight and development. Common challenges include picky eating, food allergies, and the rising prevalence of childhood obesity. Parents play a key role by modeling healthy eating, offering variety, and creating positive mealtime environments.', '{"common_symptoms":["Picky eating or food refusal in toddlers","Slow growth or failure to thrive (in nutritional deficiency)","Fatigue or low energy levels","Frequent infections due to weak immunity","Constipation from low fiber intake","Dental cavities linked to sugary diets","Difficulty concentrating at school","Unexplained weight gain or loss"],"risk_factors":["High intake of processed foods and sugary drinks","Picky eating patterns limiting food variety","Food allergies or intolerances","Socioeconomic barriers to fresh, nutritious food","Excessive screen time and sedentary habits","Skipping breakfast or irregular meals","Family history of obesity or diabetes","Lack of parental modeling of healthy eating"],"lifestyle_tips":["Offer a rainbow of fruits and vegetables daily","Include whole grains, lean proteins, and dairy in meals","Limit sugary drinks and offer water or milk instead","Establish regular family meal times without screens","Involve children in meal planning and preparation","Offer new foods repeatedly without pressure","Ensure adequate iron, calcium, and vitamin D intake","Encourage mindful eating and appropriate portion sizes"],"when_to_seek_care":"Consult a pediatrician or pediatric dietitian if your child shows poor growth, significant weight loss or gain, chronic constipation, signs of food allergy (hives, swelling, vomiting), persistent picky eating that limits nutrition, or symptoms of nutrient deficiency such as pale skin, fatigue, or brittle nails. Seek immediate care for severe allergic reactions or signs of dehydration."}'::jsonb, '["childhood-obesity","iron-deficiency-anemia","food-allergies","constipation"]'::jsonb, '["why-am-i-always-tired","why-is-my-child-not-eating"]'::jsonb, '["nutrition-assessment","bmi-calculator"]'::jsonb),
('developmental-milestones', 'Developmental Milestones', 'Track child developmental milestones from infancy to age 5: motor, language, social, and cognitive skills, and when to discuss developmental concerns with a specialist.', 'Developmental milestones are age-specific skills that mark a child''s progress across key areas of growth: gross motor (sitting, crawling, walking), fine motor (grasping, drawing), language and communication (babbling, first words, sentences), social and emotional (smiling, playing with others), and cognitive (problem-solving, pretend play). While every child develops at their own pace, milestones provide a helpful framework for monitoring progress and identifying potential delays early. Early identification of developmental concerns is critical, as timely intervention with therapies such as speech, occupational, or physical therapy can significantly improve outcomes. Parents and pediatricians track milestones together during well-child visits.', '{"common_symptoms":["Delayed speech or limited vocabulary for age","Not sitting, crawling, or walking by expected ages","Lack of eye contact or social smiling by 2-3 months","Not responding to name by 12 months","Loss of previously acquired skills (regression)","Repetitive movements or restricted interests","Difficulty interacting with peers","Trouble following simple instructions"],"risk_factors":["Premature birth or low birth weight","Genetic conditions such as Down syndrome","Exposure to toxins or infections during pregnancy","Complications during birth or oxygen deprivation","Family history of developmental disorders","Environmental factors such as lead exposure","Lack of stimulation or nurturing interaction","Hearing or vision impairments"],"lifestyle_tips":["Engage in daily reading and conversation with your child","Provide age-appropriate toys that encourage exploration","Encourage tummy time and supervised physical play for infants","Limit screen time, especially under 18 months","Sing, talk, and respond to your child''s cues consistently","Create a safe space for crawling, climbing, and movement","Attend regular well-child checkups to track milestones","Foster social interaction through playdates and group activities"],"when_to_seek_care":"Discuss developmental concerns with your pediatrician if your child misses multiple milestones, loses skills they once had, shows no babbling or pointing by 12 months, no words by 16 months, or no two-word phrases by 24 months. Ask for a developmental screening or referral to a specialist (such as a developmental pediatrician, speech therapist, or occupational therapist) for further evaluation. Early intervention is most effective when started as soon as possible."}'::jsonb, '["autism-spectrum-disorder","developmental-delay","adhd","speech-delay"]'::jsonb, '["why-is-my-child-not-talking","why-is-my-child-not-walking"]'::jsonb, '["milestone-tracker","developmental-screening"]'::jsonb),
('child-sleep', 'Child Sleep', 'Learn about child sleep: how much sleep kids need by age, sleep training methods, bedtime routines, common sleep problems, and how to build healthy sleep habits.', 'Adequate, quality sleep is vital for a child''s physical growth, brain development, emotional regulation, and immune function. Sleep needs vary by age, from 14-17 hours per day for newborns to 9-12 hours for school-age children. Many children experience sleep challenges at some point, including difficulty falling asleep, night wakings, nightmares, bedtime resistance, and parasomnias such as sleepwalking. Establishing a consistent bedtime routine, a sleep-friendly environment, and age-appropriate sleep schedules helps children develop healthy sleep habits that last a lifetime. Persistent sleep problems can affect mood, behavior, and learning, and may signal underlying medical issues such as sleep apnea.', '{"common_symptoms":["Difficulty falling asleep at bedtime","Frequent night wakings","Early morning awakening","Bedtime resistance or tantrums","Snoring or pauses in breathing during sleep","Nightmares or night terrors","Daytime sleepiness or irritability","Sleepwalking or talking during sleep"],"risk_factors":["Inconsistent bedtime routines or schedules","Excessive screen time before bed","Caffeine intake from sodas or chocolate","Overcrowded or noisy sleep environment","Stress, anxiety, or major life changes","Enlarged tonsils or adenoids (sleep apnea risk)","Lack of physical activity during the day","Co-sleeping beyond the appropriate age"],"lifestyle_tips":["Establish a consistent, calming bedtime routine","Set a regular sleep and wake time, even on weekends","Keep the bedroom dark, quiet, and comfortably cool","Avoid screens at least one hour before bedtime","Encourage physical activity during the day","Limit caffeine, especially in the afternoon and evening","Use a transitional object like a stuffed animal for comfort","Teach self-soothing skills so children can fall asleep independently"],"when_to_seek_care":"Consult a pediatrician if your child snores loudly, pauses breathing during sleep, has persistent difficulty falling or staying asleep despite good sleep habits, experiences frequent night terrors or sleepwalking, or shows excessive daytime sleepiness that affects school or behavior. A sleep specialist can evaluate for conditions like obstructive sleep apnea, insomnia, or circadian rhythm disorders."}'::jsonb, '["insomnia","sleep-apnea","adhd","anxiety"]'::jsonb, '["why-cant-i-sleep","why-is-my-child-tired"]'::jsonb, '["sleep-tracker","symptom-checker"]'::jsonb)
INSERT INTO public.seniors_health (slug, name, meta_description, description, topics, related_conditions, related_questions, related_tools) VALUES
('arthritis-management', 'Arthritis Management', 'Learn about arthritis in older adults: types like osteoarthritis and rheumatoid arthritis, symptoms, risk factors, pain management, and lifestyle tips to maintain joint health and mobility.', 'Arthritis is a leading cause of disability among older adults, encompassing more than 100 conditions that affect the joints and surrounding tissues. The two most common forms in seniors are osteoarthritis (OA), caused by wear and tear of protective cartilage, and rheumatoid arthritis (RA), an autoimmune disease causing joint inflammation. Arthritis management aims to reduce pain, control inflammation, preserve joint function, and prevent disability through a combination of medication, physical therapy, exercise, weight management, and assistive devices. Early diagnosis and a personalized care plan can significantly improve outcomes and help seniors remain active and independent.', '{"common_symptoms":["Joint pain that worsens with activity and improves with rest","Morning stiffness lasting more than 30 minutes","Swelling, tenderness, or warmth around joints","Reduced range of motion and flexibility","Crepitus (grinding or cracking sounds) during movement","Joint deformity in advanced stages","Fatigue and reduced physical function"],"risk_factors":["Age over 50","Family history of arthritis","Previous joint injury or surgery","Obesity and excess body weight","Female sex (higher risk for most types)","Repetitive joint-stressing occupations","Bone deformities or metabolic diseases"],"lifestyle_tips":["Engage in low-impact exercise such as swimming, cycling, or walking","Maintain a healthy weight to reduce stress on weight-bearing joints","Apply heat or cold packs to relieve pain and stiffness","Use assistive devices like canes or jar openers to protect joints","Practice gentle stretching and range-of-motion exercises daily","Eat an anti-inflammatory diet rich in omega-3s, fruits, and vegetables","Get adequate rest and balance activity with recovery","Work with a physical therapist on a personalized joint-protection plan"],"when_to_seek_care":"See a healthcare provider if joint pain or stiffness persists beyond a few weeks, limits daily activities, or is accompanied by swelling, redness, or warmth. Seek prompt care for sudden severe joint pain, inability to move a joint, fever with joint symptoms, or joint deformity. A rheumatologist can confirm the diagnosis and tailor a treatment plan including medications, therapy, or injections."}'::jsonb, '["osteoarthritis","rheumatoid-arthritis","osteoporosis","gout"]'::jsonb, '["why-do-my-joints-hurt","why-am-i-tired"]'::jsonb, '["symptom-checker","nutrition-assessment"]'::jsonb),
('memory-care', 'Memory Care', 'Understand memory care for seniors: causes of memory loss, signs of dementia and Alzheimer''s, risk factors, caregiving strategies, and when to seek evaluation for cognitive decline.', 'Memory care focuses on the diagnosis, support, and management of cognitive decline in older adults, with particular attention to dementia and Alzheimer''s disease. Some degree of forgetfulness is a normal part of aging, but persistent memory loss, confusion, or difficulty with familiar tasks may signal a more serious condition. Early evaluation is critical because some causes of memory impairment, such as medication effects, vitamin deficiencies, or depression, are reversible, while others, like Alzheimer''s, benefit from early intervention and planning. Memory care encompasses medical treatment, cognitive stimulation, caregiver support, environmental modifications, and safety planning to help seniors maintain dignity and independence for as long as possible.', '{"common_symptoms":["Frequently forgetting recent events or conversations","Repeating questions or stories","Misplacing items in unusual places","Difficulty finding words or following conversations","Getting lost in familiar locations","Trouble managing finances or medications","Changes in mood, personality, or judgment","Withdrawal from social activities"],"risk_factors":["Age over 65","Family history of Alzheimer''s or dementia","Cardiovascular disease, hypertension, or diabetes","Traumatic brain injury","Hearing loss and social isolation","Depression and chronic stress","Smoking and excessive alcohol use","Sedentary lifestyle and poor diet"],"lifestyle_tips":["Stay mentally active with reading, puzzles, or learning new skills","Engage in regular physical exercise to support brain blood flow","Maintain strong social connections and community involvement","Follow a Mediterranean or MIND diet rich in vegetables and fish","Get 7-8 hours of quality sleep each night","Manage cardiovascular risk factors like blood pressure and diabetes","Use calendars, reminders, and labels to support daily routines","Address hearing loss with proper evaluation and aids"],"when_to_seek_care":"Consult a healthcare provider if memory changes interfere with daily life, if you notice sudden or rapidly worsening confusion, or if there are changes in personality or judgment. Seek immediate care for sudden severe confusion, which may indicate a stroke, infection, or medication reaction. A neurologist or geriatrician can perform cognitive assessments and recommend a care plan."}'::jsonb, '["alzheimers-disease","dementia","depression","stroke"]'::jsonb, '["why-am-i-tired","why-do-i-have-headaches"]'::jsonb, '["symptom-checker","mental-health-assessment"]'::jsonb),
('fall-prevention', 'Fall Prevention', 'Learn about fall prevention for seniors: risk factors, home safety modifications, balance exercises, medication review, and strategies to reduce fall injuries and maintain independence.', 'Falls are one of the most serious and preventable health risks for older adults, often leading to fractures, head injuries, hospitalization, and loss of independence. About one in three adults over 65 falls each year, and the risk rises with age. Fall prevention requires a multifaceted approach that addresses modifiable risk factors including muscle weakness, balance problems, vision impairment, medication side effects, chronic conditions, and environmental hazards. Comprehensive fall prevention combines strength and balance training, home safety modifications, regular vision and medication reviews, proper footwear, and assistive devices when needed, empowering seniors to stay active and confident.', '{"common_symptoms":["Unsteadiness or loss of balance when walking","Dizziness or lightheadedness upon standing","Muscle weakness in the legs","Slow or shuffling gait","Difficulty getting up from a chair","Fear of falling that limits activity","Previous falls or near-falls","Foot pain or numbness"],"risk_factors":["Age over 65","History of previous falls","Muscle weakness and deconditioning","Balance or gait disorders","Vision impairment","Multiple medications (polypharmacy)","Chronic conditions like arthritis, diabetes, or Parkinson''s","Home hazards such as loose rugs, poor lighting, and lack of grab bars"],"lifestyle_tips":["Perform balance and strength exercises like tai chi or physical therapy","Remove tripping hazards and secure loose rugs","Install grab bars in bathrooms and handrails on stairs","Improve lighting throughout the home, especially at night","Wear supportive, non-slip footwear both indoors and outdoors","Have medications reviewed regularly for fall-increasing side effects","Get annual vision and hearing check-ups","Stand up slowly to prevent dizziness from blood pressure drops"],"when_to_seek_care":"Seek medical evaluation after any fall, even without obvious injury, to identify treatable causes and prevent future falls. See a doctor promptly for dizziness, new balance problems, or unsteadiness. Seek emergency care for head injury, severe pain, inability to stand, or signs of fracture after a fall. A geriatrician can perform a comprehensive fall risk assessment."}'::jsonb, '["osteoporosis","arthritis","parkinsons-disease","hypotension"]'::jsonb, '["why-am-i-dizzy","why-do-my-joints-hurt"]'::jsonb, '["symptom-checker","fitness-assessment"]'::jsonb),
('medication-management', 'Medication Management', 'Learn about medication management for seniors: polypharmacy risks, drug interactions, side effects, organizing prescriptions, and tips for safe medication use in older adults.', 'Medication management is a critical component of senior health care, as older adults often take multiple medications for chronic conditions. While these medications improve health and longevity, polypharmacy (the use of five or more medications) increases the risk of drug interactions, side effects, adherence errors, and adverse events. Age-related changes in how the body processes medications also make seniors more sensitive to their effects. Effective medication management involves maintaining an accurate medication list, regular reviews with healthcare providers and pharmacists, using organizers or reminder systems, understanding each medication''s purpose and side effects, and coordinating care among multiple specialists. These practices help prevent complications and hospitalizations while maximizing therapeutic benefits.', '{"common_symptoms":["Confusion or cognitive changes after starting a new medication","Dizziness, drowsiness, or unsteadiness","Gastrointestinal issues like nausea or constipation","Unexpected falls or weakness","Skin rashes or allergic reactions","Difficulty remembering whether a dose was taken","Using multiple pharmacies and providers","Running out of refills or taking expired medications"],"risk_factors":["Taking five or more medications (polypharmacy)","Multiple prescribing doctors and pharmacies","Cognitive impairment or memory loss","Kidney or liver function decline","Living alone without medication support","Frequent medication changes or new prescriptions","Use of over-the-counter drugs and supplements","Low health literacy or language barriers"],"lifestyle_tips":["Keep an up-to-date list of all medications, doses, and schedules","Use pill organizers or blister packs to track daily doses","Set alarms or use reminder apps for medication times","Review all medications with a doctor or pharmacist at least annually","Use a single pharmacy to coordinate and check for interactions","Ask about side effects and what to do if a dose is missed","Store medications in a cool, dry place out of reach of others","Never share medications or stop a prescription without consulting a doctor"],"when_to_seek_care":"Contact a healthcare provider or pharmacist if you experience new or worsening symptoms after starting a medication, suspect a side effect or interaction, or have trouble following your regimen. Seek emergency care for severe allergic reactions, trouble breathing, chest pain, or sudden confusion. Schedule a medication review whenever a new drug is added or a specialist changes a prescription."}'::jsonb, '["hypertension","diabetes","depression","heart-disease"]'::jsonb, '["why-am-i-dizzy","why-am-i-tired"]'::jsonb, '["symptom-checker","medication-tracker"]'::jsonb),
('healthy-aging', 'Healthy Aging', 'Discover healthy aging strategies for seniors: physical activity, nutrition, mental wellness, preventive care, and lifestyle habits that promote longevity and quality of life.', 'Healthy aging is a holistic approach to maintaining physical, mental, and social well-being throughout the later years of life. Rather than simply extending lifespan, healthy aging focuses on healthspan, the years lived in good health and with independence. It is shaped by a combination of genetics, lifestyle, environment, and access to care. Key pillars include regular physical activity, balanced nutrition, quality sleep, strong social connections, cognitive engagement, preventive healthcare, and management of chronic conditions. Adopting healthy habits at any age can reduce the risk of disease, preserve mobility and cognition, and enhance overall quality of life, allowing older adults to remain active, connected, and purposeful.', '{"common_symptoms":["Gradual decrease in muscle mass and strength","Reduced energy and slower recovery from activity","Changes in sleep patterns","Mild forgetfulness or slower recall","Decreased appetite or changes in taste","Reduced balance and flexibility","Changes in mood or social engagement","Wrinkling and loss of skin elasticity"],"risk_factors":["Sedentary lifestyle and physical inactivity","Poor diet and nutritional deficiencies","Social isolation and loneliness","Smoking and excessive alcohol consumption","Chronic stress and poor sleep","Unmanaged chronic conditions","Skipping preventive screenings and vaccinations","Limited access to healthcare and community resources"],"lifestyle_tips":["Aim for 150 minutes of moderate exercise per week, including strength training","Eat a balanced diet with plenty of fruits, vegetables, and whole grains","Stay socially active through community groups, hobbies, or volunteering","Prioritize 7-8 hours of quality sleep each night","Keep up with recommended screenings, vaccinations, and dental visits","Challenge the brain with reading, games, or new skills","Limit alcohol and avoid smoking","Practice stress management through mindfulness, nature, or faith"],"when_to_seek_care":"Schedule regular wellness visits to monitor chronic conditions and update preventive care. See a healthcare provider for new or unusual symptoms, unexplained weight loss, persistent pain, mood changes, or declining function. Seek prompt care for chest pain, sudden weakness or numbness, severe shortness of breath, or signs of a stroke. A geriatrician can help coordinate care tailored to the needs of older adults."}'::jsonb, '["hypertension","diabetes","osteoporosis","depression"]'::jsonb, '["why-am-i-tired","why-am-i-gaining-weight"]'::jsonb, '["symptom-checker","nutrition-assessment","fitness-assessment"]'::jsonb)
INSERT INTO public.pregnancy_health (slug, name, meta_description, description, topics, related_conditions, related_questions, related_tools) VALUES
('prenatal-care', 'Prenatal Care', 'Learn about prenatal care: schedule of visits, key screenings, tests, and how regular monitoring supports a healthy pregnancy for parent and baby.', 'Prenatal care is the comprehensive medical care provided throughout pregnancy to promote the health of the pregnant person and the developing fetus. It begins as soon as pregnancy is confirmed and continues until delivery. Through a schedule of regular check-ups, healthcare providers monitor fetal growth, detect complications early, manage pre-existing conditions, and provide guidance on nutrition, exercise, and lifestyle. Studies consistently show that early and adequate prenatal care significantly reduces the risk of preterm birth, low birth weight, and maternal complications. A typical schedule includes monthly visits in the first two trimesters, visits every two weeks around weeks 28 to 36, and weekly visits from week 36 until delivery.', '{"common_symptoms":["Nausea and vomiting (morning sickness)","Fatigue and increased need for sleep","Breast tenderness and enlargement","Frequent urination","Mild swelling of ankles and feet","Mood swings and emotional changes","Heartburn and constipation","Stretching sensations or mild round ligament pain"],"risk_factors":["Age under 17 or over 35","Pre-existing conditions such as diabetes, hypertension, or thyroid disease","Previous pregnancy complications including preterm birth or preeclampsia","Multiple pregnancy (twins, triplets)","Smoking, alcohol, or substance use","Low pre-pregnancy body weight or obesity","Limited access to healthcare or late initiation of care","Certain infections such as HIV, hepatitis, or syphilis"],"lifestyle_tips":["Begin prenatal care as soon as you suspect pregnancy to establish an early baseline","Take a daily prenatal vitamin containing 400 to 800 micrograms of folic acid","Keep every scheduled appointment and come prepared with questions","Track fetal movements in the third trimester as advised by your provider","Maintain a balanced diet rich in fruits, vegetables, lean protein, and whole grains","Stay hydrated and aim for at least 8 to 10 glasses of water daily","Avoid alcohol, tobacco, recreational drugs, and limit caffeine","Discuss any medications or supplements with your provider before use"],"when_to_seek_care":"Schedule your first prenatal visit as soon as you have a positive pregnancy test. Seek immediate medical attention if you experience severe abdominal pain, heavy vaginal bleeding, sudden swelling of the face or hands, severe headache with vision changes, fever above 38.3 degrees Celsius, persistent vomiting preventing fluids, or a noticeable decrease in fetal movement after week 20. Never skip scheduled visits, and contact your provider between appointments for any unusual symptoms."}'::jsonb, '["preeclampsia","gestational-diabetes","preterm-labor"]'::jsonb, '["when-should-i-start-prenatal-care","what-tests-are-done-during-pregnancy"]'::jsonb, '["due-date-calculator","symptom-checker"]'::jsonb),
('pregnancy-symptoms', 'Pregnancy Symptoms', 'Understand common pregnancy symptoms by trimester, what is normal, warning signs, and when to contact a healthcare provider.', 'Pregnancy symptoms vary widely between individuals and even between pregnancies, driven primarily by rising levels of human chorionic gonadotropin (hCG), estrogen, and progesterone. The first trimester is often marked by nausea, fatigue, breast tenderness, and frequent urination. The second trimester is typically the most comfortable, with many early symptoms easing and fetal movement beginning. The third trimester brings physical strain as the baby grows, including back pain, swelling, shortness of breath, and Braxton Hicks contractions. Recognizing which symptoms are expected and which are warning signs empowers pregnant individuals to seek timely care and reduces unnecessary anxiety during this transformative time.', '{"common_symptoms":["Missed period (often the first sign)","Nausea with or without vomiting, typically in the first trimester","Extreme fatigue, especially in early pregnancy","Breast swelling, tenderness, and darkening of the areolas","Frequent urination from early pregnancy onward","Food cravings or aversions and heightened sense of smell","Mood swings, irritability, and emotional sensitivity","Heartburn, bloating, and constipation"],"risk_factors":["Multiple pregnancy, which intensifies hormone levels and symptoms","History of motion sickness or migraines, increasing nausea risk","Pre-existing conditions such as thyroid disorders or anemia","First pregnancy, which may produce more noticeable symptoms","High stress levels and inadequate sleep","Poor nutrition or dehydration, which can worsen symptoms","Advanced maternal age"],"lifestyle_tips":["Eat small, frequent meals to manage nausea and stabilize energy","Keep crackers by your bedside and eat a few before getting up","Stay hydrated with water, herbal teas, or electrolyte drinks","Rest when tired and aim for 7 to 9 hours of sleep per night","Wear a supportive bra and loose, comfortable clothing","Use ginger or vitamin B6 (with provider approval) for nausea relief","Practice gentle exercise such as walking or prenatal yoga","Track symptoms to identify triggers and patterns to discuss with your provider"],"when_to_seek_care":"Contact your healthcare provider if you cannot keep fluids down for more than 12 hours, experience severe abdominal or pelvic pain, heavy bleeding, fever, or painful urination. Seek emergency care for sudden severe swelling with headache or vision changes, difficulty breathing, chest pain, or a sudden decrease in fetal movement after week 20. Routine symptoms that persist or significantly affect daily life should also be discussed at prenatal visits."}'::jsonb, '["morning-sickness","preeclampsia","preterm-labor"]'::jsonb, '["why-am-i-so-tired-during-pregnancy","when-do-pregnancy-symptoms-start"]'::jsonb, '["symptom-checker","due-date-calculator"]'::jsonb),
('nutrition-during-pregnancy', 'Nutrition During Pregnancy', 'Learn about nutrition during pregnancy: essential nutrients, foods to eat and avoid, weight gain guidelines, and safe supplementation.', 'Nutrition during pregnancy plays a critical role in fetal growth, brain development, and the long-term health of both parent and child. Caloric needs increase modestly, by about 300 to 450 extra calories per day in the second and third trimesters, but the need for many vitamins and minerals rises significantly. Key nutrients include folic acid to prevent neural tube defects, iron to support increased blood volume, calcium and vitamin D for fetal bone development, DHA for brain and eye development, and protein for tissue growth. Equally important is knowing which foods to avoid, such as raw or undercooked seafood, unpasteurized dairy, deli meats, high-mercury fish, and excess caffeine or alcohol. Following evidence-based guidelines helps reduce the risk of complications and supports a healthy birth weight.', '{"common_symptoms":["Increased appetite and food cravings","Food aversions, especially to meat or strong-smelling foods","Heartburn and acid reflux after meals","Constipation due to iron supplements and hormonal changes","Nausea that can limit food tolerance","Heightened sense of smell affecting food choices","Swelling related to high sodium intake","Fatigue linked to low iron or inadequate calories"],"risk_factors":["Pre-existing nutrient deficiencies such as anemia or low vitamin D","Vegetarian, vegan, or highly restrictive diets","Multiple pregnancy, which requires higher nutrient intake","Adolescent pregnancy, where the parent is still growing","Food insecurity or limited access to fresh foods","History of eating disorders","Excessive caffeine or alcohol consumption","Gestational diabetes requiring dietary control"],"lifestyle_tips":["Take a daily prenatal vitamin with 400 to 800 mcg of folic acid throughout pregnancy","Include at least 27 mg of iron daily from lean meats, legumes, and fortified grains","Eat 2 to 3 servings of low-mercury fish such as salmon or sardines per week for DHA","Aim for 1,000 mg of calcium daily from dairy, fortified plant milks, or leafy greens","Stay hydrated with at least 8 to 10 glasses of water daily","Avoid raw fish, unpasteurized cheese, deli meats, and high-mercury fish","Limit caffeine to 200 mg per day (about one 12-ounce coffee)","Choose whole grains, fruits, and vegetables to manage constipation and blood sugar"],"when_to_seek_care":"Consult your healthcare provider or a registered dietitian if you experience persistent vomiting that prevents adequate nutrition, rapid or inadequate weight gain, signs of anemia such as severe fatigue or paleness, or cravings for non-food items such as ice, clay, or starch (a condition called pica). Seek urgent care for signs of foodborne illness including fever, diarrhea, or dehydration after eating suspect foods."}'::jsonb, '["gestational-diabetes","anemia","preeclampsia"]'::jsonb, '["what-foods-should-i-avoid-during-pregnancy","how-much-weight-should-i-gain-in-pregnancy"]'::jsonb, '["pregnancy-nutrition-guide","symptom-checker"]'::jsonb),
('exercise-in-pregnancy', 'Exercise in Pregnancy', 'Learn about exercise in pregnancy: safe activities, guidelines, benefits, warning signs to stop, and how to stay active safely.', 'Regular exercise during pregnancy is strongly recommended by major health organizations for most pregnant individuals without complications. The American College of Obstetricians and Gynecologists (ACOG) recommends at least 150 minutes of moderate-intensity activity per week, spread across several days. Safe options include brisk walking, swimming, stationary cycling, and prenatal yoga or Pilates. Exercise helps reduce back pain, ease constipation, lower the risk of gestational diabetes and preeclampsia, support healthy weight gain, improve sleep, and boost mood. It also builds stamina for labor and supports faster postpartum recovery. Certain activities should be avoided, including contact sports, activities with a high risk of falling, scuba diving, and exercising flat on the back after the first trimester. Individuals with high-risk pregnancies should consult their provider for a personalized plan.', '{"common_symptoms":["Round ligament pain during movement","Shortness of breath, especially in the third trimester","Lower back pain and pelvic pressure","Increased sweating and feeling warmer than usual","Braxton Hicks contractions after vigorous activity","Swelling of the feet and ankles after exercise","Heartburn during or after workouts","Decreased balance as the center of gravity shifts"],"risk_factors":["High-risk conditions such as preeclampsia or placenta previa","History of preterm labor or cervical insufficiency","Multiple pregnancy requiring modified activity","Severe anemia or uncontrolled heart disease","Inexperienced exercisers starting intense programs too quickly","Dehydration and exercising in hot, humid environments","Pre-existing joint or back problems","First-time pregnancy without guidance on safe movements"],"lifestyle_tips":["Aim for 150 minutes of moderate exercise per week, such as 30 minutes on 5 days","Choose low-impact activities like walking, swimming, or prenatal yoga","Always warm up for 5 to 10 minutes and cool down afterward","Drink water before, during, and after exercise to stay hydrated","Avoid exercising flat on your back after the first trimester","Use the ''talk test'': you should be able to hold a conversation during activity","Listen to your body and reduce intensity as pregnancy progresses","Wear supportive footwear and a well-fitted maternity bra"],"when_to_seek_care":"Stop exercising and contact your healthcare provider immediately if you experience vaginal bleeding, painful contractions before 37 weeks, chest pain, dizziness or fainting, calf pain or swelling, muscle weakness, or fluid leaking from the vagina. Also seek guidance if you develop shortness of breath before exertion, irregular heartbeat, or a sudden drop in energy. Always discuss your exercise plan with your provider, especially if you have any pregnancy complications."}'::jsonb, '["gestational-diabetes","preeclampsia","preterm-labor"]'::jsonb, '["is-it-safe-to-exercise-during-pregnancy","what-exercises-should-i-avoid-while-pregnant"]'::jsonb, '["pregnancy-fitness-guide","symptom-checker"]'::jsonb),
('childbirth-preparation', 'Childbirth Preparation', 'Learn about childbirth preparation: birth plans, classes, labor stages, pain management, packing lists, and what to expect on delivery day.', 'Childbirth preparation is the process of getting ready for labor, delivery, and the early postpartum period through education, planning, and practical arrangements. It typically begins in the second or early third trimester and includes attending childbirth classes, learning about the stages of labor, exploring pain management options, drafting a birth plan, packing a hospital bag, and arranging support for after the birth. Understanding what to expect helps reduce fear, supports informed decision-making, and improves the overall birth experience. Preparation also includes choosing a healthcare team and birth setting, understanding possible interventions, and recognizing the signs of labor so that parents know when to head to the hospital or call their provider.', '{"common_symptoms":["Braxton Hicks contractions becoming more noticeable in late pregnancy","Increased back pain and pelvic pressure as the baby drops","Frequent urination as the baby presses on the bladder","Difficulty sleeping due to discomfort and anticipation","Nesting instinct and bursts of energy","Loose joints and changes in balance","Lightening (baby settling lower into the pelvis)","Loss of the mucus plug or bloody show as labor approaches"],"risk_factors":["First pregnancy with limited exposure to the birth process","High-risk pregnancy requiring specialized birth planning","Anxiety or fear of childbirth (tokophobia)","Limited support system or birth partner availability","Previous traumatic birth experience","Late start to preparation, leaving little time for classes","Pre-existing medical conditions influencing delivery options","Plans for vaginal birth after cesarean (VBAC)"],"lifestyle_tips":["Enroll in a childbirth education class by the third trimester","Draft a birth plan covering pain management, positions, and preferences","Pack a hospital bag by week 36 with essentials for you, baby, and partner","Practice breathing and relaxation techniques daily","Learn the signs of labor: contractions, water breaking, and bloody show","Tour your birth facility and confirm registration in advance","Discuss pain relief options with your provider, including epidural and natural methods","Arrange postpartum support for meals, childcare, and household tasks"],"when_to_seek_care":"Head to the hospital or contact your provider if you experience regular contractions 5 minutes apart lasting 1 minute each for at least 1 hour (5-1-1 rule), your water breaks (especially if the fluid is green, brown, or foul-smelling), you have heavy vaginal bleeding, or you notice a sudden decrease in fetal movement. Seek immediate care for severe abdominal pain, sudden severe headache, vision changes, or fever before your due date. If you are unsure whether you are in labor, call your provider for guidance."}'::jsonb, '["preterm-labor","preeclampsia","postpartum-depression"]'::jsonb, '["how-do-i-know-when-im-in-labor","what-should-i-pack-for-the-hospital"]'::jsonb, '["birth-plan-builder","contraction-timer"]'::jsonb)
INSERT INTO public.faq_questions (slug, question, meta_description, answer, category, related_conditions, related_symptoms, related_questions, related_tools, difficulty, is_common, search_volume) VALUES
('why-am-i-tired', 'Why am I always tired?', 'Discover the common causes of persistent fatigue and effective solutions for increasing your energy levels.', 'Feeling constantly tired is a common complaint with many potential causes. Common reasons include sleep deprivation, poor sleep quality, stress, anxiety, depression, nutrient deficiencies (like iron or vitamin D), dehydration, sedentary lifestyle, and underlying health conditions such as anemia, thyroid disorders, or chronic fatigue syndrome. Lifestyle factors like excessive caffeine, alcohol consumption, and poor diet can also contribute. To improve energy levels, focus on getting 7-9 hours of quality sleep nightly, maintaining a balanced diet, staying hydrated, exercising regularly, managing stress, and limiting caffeine and alcohol. If fatigue persists despite these changes, consult a healthcare provider to rule out underlying medical conditions.', 'Fatigue', '["insomnia","depression","anemia","hypothyroidism"]'::jsonb, '["fatigue","weakness","sleepiness"]'::jsonb, '["why-can''t-i-sleep","why-do-i-have-no-energy"]'::jsonb, '["sleep-checker","stress-assessment","nutrition-assessment"]'::jsonb, 'Common', TRUE, 301000),
('why-is-my-nose-blocked', 'Why is my nose blocked?', 'Learn about the common causes of nasal congestion and effective ways to relieve a stuffy nose.', 'Nasal congestion, or a blocked nose, is usually caused by inflammation of the nasal passages. Common causes include allergies (hay fever), colds and flu, sinus infections, nasal polyps, deviated septum, and environmental irritants like smoke or dust. Allergic rhinitis is a frequent cause, triggered by pollen, dust mites, or pet dander. Sinusitis can cause persistent congestion along with facial pain and pressure. Home remedies include using a humidifier, saline nasal sprays, staying hydrated, and avoiding irritants. Over-the-counter decongestants and antihistamines can also help. If congestion persists for more than a week, is accompanied by severe pain or fever, or affects breathing, consult a healthcare provider.', 'Respiratory', '["sinusitis","allergies","rhinitis","cold"]'::jsonb, '["nasal-congestion","runny-nose","sneezing"]'::jsonb, '["why-do-i-snore","why-am-i-sneezing"]'::jsonb, '["symptom-checker","allergy-assessment"]'::jsonb, 'Common', TRUE, 90500),
('why-do-i-have-headaches', 'Why do I have headaches?', 'Understanding the common causes of headaches and effective strategies for prevention and relief.', 'Headaches can have many causes, ranging from minor to serious. Common causes include tension (from stress, poor posture, or muscle tightness), migraines (often accompanied by sensitivity to light and nausea), sinus pressure (from allergies or infections), dehydration, lack of sleep, skipped meals, and eye strain. Less common but serious causes include high blood pressure, brain tumors, and meningitis. To manage headaches, identify triggers by keeping a headache diary, practice relaxation techniques, stay hydrated, get enough sleep, and maintain good posture. Over-the-counter pain relievers can help with mild headaches. Seek medical attention for severe, sudden headaches, headaches accompanied by neurological symptoms, or persistent headaches that don''t respond to treatment.', 'Neurological', '["migraine","tension-headache","sinusitis","hypertension"]'::jsonb, '["headache","nausea","sensitivity-to-light"]'::jsonb, '["why-am-i-dizzy","why-do-my-eyes-hurt"]'::jsonb, '["symptom-checker","stress-assessment"]'::jsonb, 'Common', TRUE, 152000),
('why-am-i-bloated', 'Why am I bloated?', 'Discover the common causes of bloating and effective ways to reduce abdominal discomfort.', 'Bloating is a feeling of fullness or tightness in the abdomen, often caused by excess gas or fluid. Common causes include eating too quickly, swallowing air, consuming gas-producing foods (like beans, lentils, broccoli, and carbonated drinks), lactose intolerance, irritable bowel syndrome (IBS), constipation, and food allergies. Hormonal changes, particularly in women during the menstrual cycle, can also cause bloating. To reduce bloating, eat slowly, avoid carbonated drinks, limit gas-producing foods, stay hydrated, exercise regularly, and practice stress management. Over-the-counter products like simethicone can help relieve gas. If bloating is persistent, severe, or accompanied by weight loss, pain, or changes in bowel habits, consult a healthcare provider.', 'Digestive', '["ibs","lactose-intolerance","constipation","food-allergies"]'::jsonb, '["abdominal-pain","gas","distension"]'::jsonb, '["why-does-my-stomach-hurt","why-am-i-gassy"]'::jsonb, '["symptom-checker","digestive-checker"]'::jsonb, 'Common', TRUE, 82000),
('why-can-i-not-sleep', 'Why can''t I sleep?', 'Understanding insomnia and effective strategies for improving your sleep quality.', 'Difficulty sleeping (insomnia) can be caused by many factors. Common causes include stress, anxiety, depression, irregular sleep schedule, caffeine or alcohol consumption, electronic device use before bed, uncomfortable sleep environment, and underlying health conditions like chronic pain, thyroid disorders, or sleep apnea. Lifestyle habits play a significant role—using screens before bed exposes you to blue light that suppresses melatonin, while caffeine and alcohol disrupt normal sleep patterns. To improve sleep, establish a regular sleep schedule, create a relaxing bedtime routine, optimize your sleep environment (dark, quiet, cool), limit screen time before bed, avoid caffeine and alcohol, and exercise regularly. If insomnia persists for more than 3 months or affects daily functioning, consult a healthcare provider.', 'Sleep', '["insomnia","anxiety","depression","sleep-apnea"]'::jsonb, '["fatigue","difficulty-falling-asleep","early-morning-awakening"]'::jsonb, '["why-am-i-tired","why-do-i-wake-up-at-night"]'::jsonb, '["sleep-checker","stress-assessment"]'::jsonb, 'Common', TRUE, 181000),
('why-am-i-anxious', 'Why am I anxious?', 'Understanding anxiety: common causes, symptoms, and effective strategies for managing worry and fear.', 'Anxiety is a normal human response to stress, but when it becomes excessive or persistent, it can be debilitating. Common causes include genetic factors, brain chemistry imbalances, environmental stressors (work pressure, relationship issues, financial concerns), traumatic experiences, and chronic health conditions. Personality traits like perfectionism or overthinking can also contribute. Symptoms may include excessive worry, restlessness, difficulty concentrating, irritability, muscle tension, and panic attacks. To manage anxiety, practice relaxation techniques like deep breathing or meditation, exercise regularly, maintain a healthy diet, get enough sleep, and limit caffeine and alcohol. Cognitive-behavioral therapy (CBT) and medication can be effective for persistent anxiety. If anxiety interferes with daily life, seek professional help.', 'Mental Health', '["anxiety-disorder","panic-disorder","depression","ptsd"]'::jsonb, '["nervousness","restlessness","heart-palpitations"]'::jsonb, '["why-do-i-feel-stressed","why-am-i-worried"]'::jsonb, '["stress-assessment","anxiety-checker"]'::jsonb, 'Common', TRUE, 110000),
('why-am-i-gaining-weight', 'Why am I gaining weight?', 'Understanding weight gain: common causes and effective strategies for healthy weight management.', 'Weight gain typically occurs when calorie intake exceeds calorie expenditure over time. Common causes include poor diet (high in processed foods, sugar, and unhealthy fats), lack of physical activity, genetics, hormonal changes (thyroid disorders, menopause, pregnancy), medications (antidepressants, corticosteroids), stress and emotional eating, and insufficient sleep. Medical conditions like polycystic ovary syndrome (PCOS) and insulin resistance can also contribute. To manage weight, focus on balanced nutrition with whole foods, regular physical activity (at least 150 minutes weekly), staying hydrated, getting enough sleep, and managing stress. If weight gain is rapid or accompanied by other symptoms, consult a healthcare provider to rule out underlying conditions.', 'Weight Management', '["obesity","hypothyroidism","pcos","insulin-resistance"]'::jsonb, '["fatigue","increased-appetite","water-retention"]'::jsonb, '["why-am-i-hungry","why-do-i-crave-sugar"]'::jsonb, '["nutrition-assessment","symptom-checker"]'::jsonb, 'Common', TRUE, 135000),
('why-do-i-have-acne', 'Why do I have acne?', 'Understanding acne: causes, types, and effective treatment options for clear skin.', 'Acne is a common skin condition caused by clogged pores due to excess oil, dead skin cells, and bacteria. Hormonal changes (puberty, menstrual cycle, pregnancy), genetics, diet (high-glycemic foods, dairy), stress, and certain medications can trigger or worsen acne. The main types are whiteheads, blackheads, papules, pustules, nodules, and cysts. To manage acne, practice good skincare (cleanse gently, avoid overwashing), avoid touching or picking at acne, use non-comedogenic products, manage stress, and maintain a balanced diet. Over-the-counter treatments containing benzoyl peroxide or salicylic acid can help mild acne. For moderate to severe acne, consult a dermatologist who may recommend prescription medications like retinoids or antibiotics.', 'Skin', '["acne-vulgaris","rosacea","eczema","hormonal-acne"]'::jsonb, '["pimples","blackheads","redness"]'::jsonb, '["why-is-my-skin-oily","why-do-i-get-pimples"]'::jsonb, '["skin-assessment","hormone-checker"]'::jsonb, 'Common', TRUE, 165000),
('why-am-i-sore-after-working-out', 'Why am I sore after working out?', 'Understanding muscle soreness: causes, prevention, and effective recovery strategies.', 'Muscle soreness after exercise, known as delayed onset muscle soreness (DOMS), is caused by microscopic damage to muscle fibers during intense or unfamiliar exercise. The soreness typically peaks 24-72 hours after workout and is a normal part of muscle adaptation. Factors that contribute include high-intensity exercise, eccentric movements (lowering phase), and new exercise routines. To reduce DOMS, warm up properly before exercise, cool down with stretching, gradually increase exercise intensity, stay hydrated, and eat a balanced diet with protein for muscle repair. Gentle movement like walking can also help increase blood flow and reduce soreness. If soreness is severe, persistent, or accompanied by swelling or redness, it may indicate injury—seek medical attention.', 'Fitness', '["muscle-strain","overtraining","dehydration"]'::jsonb, '["muscle-pain","stiffness","fatigue"]'::jsonb, '["why-do-my-muscles-hurt","how-do-i-recover-faster"]'::jsonb, '["fitness-assessment","nutrition-assessment"]'::jsonb, 'Common', TRUE, 45000),
('why-do-my-joints-hurt', 'Why do my joints hurt?', 'Understanding joint pain: common causes, symptoms, and effective treatment options for joint health.', 'Joint pain can stem from many causes, including arthritis (osteoarthritis, rheumatoid arthritis), injury, inflammation, overuse, and infection. Osteoarthritis is the most common cause, resulting from wear and tear on joint cartilage over time. Rheumatoid arthritis is an autoimmune condition that causes joint inflammation. Other causes include gout, bursitis, tendinitis, and fibromyalgia. Symptoms may include pain, stiffness, swelling, redness, and decreased mobility. To manage joint pain, maintain a healthy weight, exercise regularly (low-impact activities like swimming or cycling), use heat or cold therapy, practice good posture, and avoid repetitive movements. Over-the-counter pain relievers and anti-inflammatories can help. For persistent or severe joint pain, consult a rheumatologist or orthopedic specialist.', 'Musculoskeletal', '["arthritis","osteoarthritis","rheumatoid-arthritis","gout"]'::jsonb, '["joint-pain","stiffness","swelling"]'::jsonb, '["why-is-my-knee-swollen","why-does-my-hip-hurt"]'::jsonb, '["symptom-checker","pain-assessment"]'::jsonb, 'Common', TRUE, 82000)
